            <div className="flex items-center gap-3">
              <div className="w-9 h-9 rounded-full bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center">
                <UserCheck size={16} className="text-white" />
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-semibold text-white truncate">Super Admin</p>
                <p className="text-[10px] text-gray-500">admin@thenijobs.com</p>
              </div>
              <button onClick={handleLogout} title="Logout" className="p-2 rounded-lg text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 transition-all">
                <LogOut size={16} />
              </button>
            </div>
          )}
        </div>
      </aside>

      {/* Main Content Area */}
      <div className={`flex-1 flex flex-col transition-all duration-300 ${collapsed ? 'lg:ml-[72px]' : 'lg:ml-[280px]'}`}>
        {/* Top Header Bar */}
        <header className="sticky top-0 z-30 h-16 bg-[#0a0a1a]/80 backdrop-blur-xl border-b border-white/[0.06] flex items-center px-4 lg:px-6 gap-4">
          {/* Mobile Menu Toggle */}
          <button
            onClick={() => setMobileOpen(true)}
            className="lg:hidden p-2 rounded-xl text-gray-400 hover:text-white hover:bg-white/[0.06] transition-all"
          >
            <Menu size={20} />
          </button>

          {/* Search Bar */}
          <div className="flex-1 max-w-lg relative hidden sm:block">
            <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
            <input
              type="text"
              placeholder="Search users, businesses, jobs..."
              className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white placeholder:text-gray-600 focus:border-violet-500/40 focus:bg-white/[0.06] outline-none transition-all"
            />
          </div>

          <div className="flex-1 sm:hidden" />

          {/* Header Actions */}
          <div className="flex items-center gap-2">
            {/* Notifications */}
            <div className="relative">
              <button
                onClick={() => setShowNotifDropdown(!showNotifDropdown)}
                className="relative p-2.5 rounded-xl text-gray-400 hover:text-white hover:bg-white/[0.06] transition-all"
              >
                <Bell size={18} />
                {unreadCount > 0 && (
                  <span className="absolute top-1.5 right-1.5 w-4 h-4 bg-rose-500 text-white text-[9px] font-bold rounded-full flex items-center justify-center">
                    {unreadCount}
                  </span>
                )}
              </button>

              {/* Notification Dropdown */}
              {showNotifDropdown && (
                <div className="absolute right-0 mt-2 w-80 rounded-2xl bg-[#0d0d20] border border-white/[0.08] shadow-[0_10px_30px_rgba(0,0,0,0.5)] z-50 overflow-hidden font-outfit">
                  <div className="px-4 py-3 border-b border-white/[0.06] flex items-center justify-between">
                    <span className="text-xs font-bold text-white">Notifications</span>
                    {unreadCount > 0 && (
                      <button
                        onClick={async () => {
                          await markAllAsRead();
                          setShowNotifDropdown(false);
                        }}
                        className="text-[10px] text-cyan-400 hover:text-cyan-300 font-bold"
                      >
                        Mark all as read
                      </button>
                    )}
                  </div>
                  <div className="max-h-64 overflow-y-auto divide-y divide-white/[0.04] no-scrollbar">
                    {notifications.length === 0 ? (
                      <div className="px-4 py-6 text-center text-xs text-gray-500">
                        You&apos;re all caught up!
                      </div>
                    ) : (
                      notifications.slice(0, 5).map((n) => (
                        <div
                          key={n.id}
                          onClick={async () => {
                            await markAsRead(n.id);
                            setShowNotifDropdown(false);
                            if (n.actionUrl) {
                              router.push(n.actionUrl);
                            }
                          }}
                          className={`px-4 py-3 hover:bg-white/[0.02] cursor-pointer transition-colors ${!n.read ? 'bg-cyan-500/[0.03]' : ''}`}
                        >
                          <p className="text-xs font-bold text-white leading-tight">{n.title}</p>
                          <p className="text-[11px] text-gray-400 mt-1 leading-snug">{n.message}</p>
                        </div>
                      ))
                    )}
                  </div>
                  <div className="px-4 py-2 border-t border-white/[0.06] text-center bg-white/[0.01]">
                    <Link
                      href="/admin/notifications"
                      onClick={() => setShowNotifDropdown(false)}
                      className="text-[11px] text-violet-400 hover:text-violet-300 font-bold block"
                    >
                      View all notifications
                    </Link>
                  </div>
                </div>
              )}
            </div>

            {/* Admin Avatar */}
            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center cursor-pointer hover:opacity-90 transition-opacity">
              <span className="text-white text-xs font-bold">SA</span>
            </div>
          </div>
        </header>

        {/* Page Content */}
        <main className="flex-1 p-4 lg:p-6 overflow-auto">
          {children}
        </main>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import {
  TrendingUp, Search, ChevronDown, Phone, Mail,
  MessageSquare, Download, User, Building2, Wrench,
  ArrowRight, Clock, CheckCircle, ChevronRight,
  Calendar, Loader2
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { updateLeadStatus } from '@/lib/firebase/firestoreService';

// ===== TYPES =====
interface LeadDoc {
  id: string;
  contactName: string;
  phone: string;
  email: string;
  company?: string;
  source?: string;
  type: 'candidate' | 'business' | 'service';
  status: LeadStatus;
  assignedTo?: string;
  createdAt?: any;
  notes?: string;
  district?: string;
}

type LeadStatus = 'new' | 'contacted' | 'qualified' | 'converted' | 'lost';

// ===== CONSTANTS =====
const STATUS_CONFIG: Record<LeadStatus, { label: string; bg: string; text: string; dot: string; borderColor: string }> = {
  new: { label: 'New', bg: 'bg-cyan-500/15', text: 'text-cyan-400', dot: 'bg-cyan-400', borderColor: 'border-cyan-500/30' },
  contacted: { label: 'Contacted', bg: 'bg-violet-500/15', text: 'text-violet-400', dot: 'bg-violet-400', borderColor: 'border-violet-500/30' },
  qualified: { label: 'Qualified', bg: 'bg-amber-500/15', text: 'text-amber-400', dot: 'bg-amber-400', borderColor: 'border-amber-500/30' },
  converted: { label: 'Converted', bg: 'bg-emerald-500/15', text: 'text-emerald-400', dot: 'bg-emerald-400', borderColor: 'border-emerald-500/30' },
  lost: { label: 'Lost', bg: 'bg-rose-500/15', text: 'text-rose-400', dot: 'bg-rose-400', borderColor: 'border-rose-500/30' },
};

const TYPE_CONFIG: Record<string, { label: string; icon: typeof User; bg: string; text: string }> = {
  candidate: { label: 'Candidate', icon: User, bg: 'bg-cyan-500/10', text: 'text-cyan-400' },
  business: { label: 'Business', icon: Building2, bg: 'bg-violet-500/10', text: 'text-violet-400' },
  service: { label: 'Service', icon: Wrench, bg: 'bg-amber-500/10', text: 'text-amber-400' },
};

const PIPELINE_STAGES: { status: LeadStatus; label: string }[] = [
  { status: 'new', label: 'New' },
  { status: 'contacted', label: 'Contacted' },
  { status: 'qualified', label: 'Qualified' },
  { status: 'converted', label: 'Converted' },
  { status: 'lost', label: 'Lost' },
];

export default function LeadsPage() {
  const { data: leads, loading } = useCollection<LeadDoc>('leads');
  const [searchQuery, setSearchQuery] = useState('');
  const [typeFilter, setTypeFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [expandedLead, setExpandedLead] = useState<string | null>(null);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const filteredLeads = leads.filter((lead) => {
    const contactName = lead.contactName || '';
    const company = lead.company || '';
    const matchSearch = contactName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      company.toLowerCase().includes(searchQuery.toLowerCase());

    const leadType = lead.type || 'candidate';
    const matchType = typeFilter === 'all' || leadType === typeFilter;

    const leadStatus = lead.status || 'new';
    const matchStatus = statusFilter === 'all' || leadStatus === statusFilter;

    return matchSearch && matchType && matchStatus;
  });

  const handleStatusChange = async (leadId: string, newStatus: LeadStatus) => {
    setActionLoading(leadId);
    try {
      await updateLeadStatus(leadId, newStatus);
    } catch (err) {
      console.error('Update lead status error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Dynamic pipeline stats
  const totalCount = leads.length;
  const newCount = leads.filter((l) => (l.status || 'new') === 'new').length;
  const contactedCount = leads.filter((l) => l.status === 'contacted').length;
  const qualifiedCount = leads.filter((l) => l.status === 'qualified').length;
  const convertedCount = leads.filter((l) => l.status === 'converted').length;

  const stats = [
    { label: 'Total Leads', value: totalCount, icon: TrendingUp, color: 'violet' },
    { label: 'New', value: newCount, icon: Clock, color: 'cyan' },
    { label: 'Contacted', value: contactedCount, icon: Phone, color: 'violet' },
    { label: 'Qualified', value: qualifiedCount, icon: CheckCircle, color: 'amber' },
    { label: 'Converted', value: convertedCount, icon: TrendingUp, color: 'emerald' },
  ];

  const statColorMap: Record<string, { bg: string; text: string }> = {
    violet: { bg: 'bg-violet-500/15', text: 'text-violet-400' },
    cyan: { bg: 'bg-cyan-500/15', text: 'text-cyan-400' },
    amber: { bg: 'bg-amber-500/15', text: 'text-amber-400' },
    emerald: { bg: 'bg-emerald-500/15', text: 'text-emerald-400' },
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">Lead Management</h1>
          <p className="text-sm text-gray-400 mt-1">Track and manage potential customers through your pipeline</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-gray-300 hover:bg-white/[0.08] hover:border-white/[0.15] transition-all">
            <Download size={16} />
            <span className="hidden sm:inline">Export</span>
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-4">
        {stats.map((stat) => {
          const colors = statColorMap[stat.color];
          const Icon = stat.icon;
          return (
            <div key={stat.label} className="glass-card rounded-2xl p-4 hover:border-white/[0.15] transition-all">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-xl ${colors.bg} flex items-center justify-center`}>
                  <Icon size={18} className={colors.text} />
                </div>
                <div>
                  <p className="text-lg font-bold text-white font-outfit">{stat.value}</p>
                  <p className="text-[10px] text-gray-500">{stat.label}</p>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Pipeline Visual */}
      <div className="glass-card rounded-2xl p-5">
        <h2 className="text-sm font-semibold text-white mb-4">Lead Pipeline</h2>
        <div className="flex items-stretch gap-2 overflow-x-auto no-scrollbar pb-2">
          {PIPELINE_STAGES.map((stage, idx) => {
            const cfg = STATUS_CONFIG[stage.status];
            const count = leads.filter((l) => (l.status || 'new') === stage.status).length;
            return (
              <div key={stage.status} className="flex items-center gap-2 flex-1 min-w-[120px]">
                <div className={`flex-1 rounded-xl p-4 ${cfg.bg} border ${cfg.borderColor} text-center`}>
                  <p className={`text-2xl font-bold ${cfg.text} font-outfit`}>{count}</p>
                  <p className="text-xs text-gray-400 mt-1">{stage.label}</p>
                </div>
                {idx < PIPELINE_STAGES.length - 1 && (
                  <ArrowRight size={16} className="text-gray-600 flex-shrink-0" />
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Search & Filters */}
      <div className="flex flex-col lg:flex-row gap-3">
        <div className="relative flex-1">
          <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
          <input
            type="text"
            placeholder="Search leads by name or company..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="search-input w-full pl-10 pr-4 py-2.5 text-sm"
          />
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer">
              <option value="all">All Types</option>
              <option value="candidate">Candidate</option>
              <option value="business">Business</option>
              <option value="service">Service</option>
            </select>
            <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
          </div>
          <div className="relative">
            <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer">
              <option value="all">All Status</option>
              <option value="new">New</option>
              <option value="contacted">Contacted</option>
              <option value="qualified">Qualified</option>
              <option value="converted">Converted</option>
              <option value="lost">Lost</option>
            </select>
            <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
          </div>
        </div>
      </div>

      {/* Leads Table */}
      <div className="glass-card rounded-2xl overflow-hidden">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <Loader2 size={36} className="text-violet-400 animate-spin mb-4" />
            <p className="text-sm text-gray-400">Loading leads from Firestore...</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-white/[0.06]">
                  <th className="text-left px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Contact</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden md:table-cell">Company / Source</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Type</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden lg:table-cell">Assigned To</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden xl:table-cell">Date</th>
                  <th className="text-right px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/[0.04]">
                {filteredLeads.map((lead) => {
                  const leadStatus = lead.status || 'new';
                  const statusCfg = STATUS_CONFIG[leadStatus];
                  const leadType = lead.type || 'candidate';
                  const typeCfg = TYPE_CONFIG[leadType] || TYPE_CONFIG.candidate;
                  const TypeIcon = typeCfg.icon;
                  const isExpanded = expandedLead === lead.id;

                  return (
                    <tr key={lead.id} className="hover:bg-white/[0.02] transition-colors cursor-pointer" onClick={() => setExpandedLead(isExpanded ? null : lead.id)}>
                      <td className="px-5 py-3.5">
                        <div className="flex items-center gap-3">
                          <div className={`w-9 h-9 rounded-full ${typeCfg.bg} flex items-center justify-center flex-shrink-0`}>
                            <TypeIcon size={16} className={typeCfg.text} />
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-white truncate">{lead.contactName}</p>
                            <p className="text-xs text-gray-500 truncate">{lead.phone}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3.5 hidden md:table-cell">
                        <p className="text-sm text-gray-300">{lead.company || 'Personal'}</p>
                        <p className="text-[10px] text-gray-600">via {lead.source || 'Website'}</p>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${typeCfg.bg} ${typeCfg.text}`}>
                          {typeCfg.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5" onClick={(e) => e.stopPropagation()}>
                        {actionLoading === lead.id ? (
                          <Loader2 size={14} className="text-violet-400 animate-spin" />
                        ) : (
                          <div className="relative">
                            <select
                              value={leadStatus}
                              onChange={(e) => handleStatusChange(lead.id, e.target.value as LeadStatus)}
                              className={`pl-2 pr-7 py-1 rounded-lg text-xs font-semibold ${statusCfg.bg} ${statusCfg.text} outline-none cursor-pointer border border-transparent hover:border-white/10`}
                            >
                              <option value="new" className="bg-black text-white">New</option>
                              <option value="contacted" className="bg-black text-white">Contacted</option>
                              <option value="qualified" className="bg-black text-white">Qualified</option>
                              <option value="converted" className="bg-black text-white">Converted</option>
                              <option value="lost" className="bg-black text-white">Lost</option>
                            </select>
                          </div>
                        )}
                      </td>
                      <td className="px-4 py-3.5 hidden lg:table-cell">
                        <span className="text-sm text-gray-300">{lead.assignedTo || 'Unassigned'}</span>
                      </td>
                      <td className="px-4 py-3.5 hidden xl:table-cell">
                        <span className="text-sm text-gray-400">
                          {lead.createdAt ? new Date(lead.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : 'N/A'}
                        </span>
                      </td>
                      <td className="px-5 py-3.5">
                        <div className="flex items-center justify-end gap-1">
                          <a href={`tel:${lead.phone}`} className="p-2 rounded-lg text-gray-400 hover:text-cyan-400 hover:bg-cyan-500/10 transition-all" title="Call" onClick={(e) => e.stopPropagation()}>
                            <Phone size={15} />
                          </a>
                          <a href={`mailto:${lead.email}`} className="p-2 rounded-lg text-gray-400 hover:text-violet-400 hover:bg-violet-500/10 transition-all" title="Email" onClick={(e) => e.stopPropagation()}>
                            <Mail size={15} />
                          </a>
                          <ChevronRight size={15} className={`text-gray-600 transition-transform ${isExpanded ? 'rotate-90' : ''}`} />
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* Empty State */}
        {!loading && filteredLeads.length === 0 && (
          <div className="flex flex-col items-center justify-center py-16">
            <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
              <TrendingUp size={28} className="text-gray-600" />
            </div>
            <p className="text-sm font-medium text-gray-400">No leads found</p>
            <p className="text-xs text-gray-600 mt-1">Try adjusting your search or filters</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import {
  Bell, Send, Mail, Smartphone, Users, Building2, MapPin, Globe, Loader2, ChevronDown, CheckCircle, Clock
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { useAuth } from '@/hooks/useAuth';
import { createDocument, getUsers, createNotification } from '@/lib/firebase/firestoreService';
import { orderBy, limit } from 'firebase/firestore';

// ===== TYPES =====
interface BroadcastDoc {
  id: string;
  title: string;
  message: string;
  type: 'push' | 'sms' | 'email';
  audience: string;
  sentAt?: any;
  status: 'sent' | 'scheduled' | 'draft';
  stats?: { sent: number; delivered: number; opened: number };
}

// ===== CONSTANTS =====
const TABS = ['Push Notifications', 'SMS Broadcast', 'Email Campaign'] as const;

const TYPE_CONFIG: Record<string, { icon: any; bg: string; text: string }> = {
  push: { icon: Bell, bg: 'bg-violet-500/10', text: 'text-violet-400' },
  sms: { icon: Smartphone, bg: 'bg-cyan-500/10', text: 'text-cyan-400' },
  email: { icon: Mail, bg: 'bg-emerald-500/10', text: 'text-emerald-400' },
};

const AUDIENCE_OPTIONS = [
  { value: 'all', label: 'All Users', icon: Globe },
  { value: 'job_seekers', label: 'Job Seekers', icon: Users },
  { value: 'employers', label: 'Employers & Business Owners', icon: Building2 },
];

export default function NotificationsPage() {
  const { user: currentUser } = useAuth();
  const { data: broadcasts, loading } = useCollection<BroadcastDoc>('broadcasts', [
    orderBy('createdAt', 'desc'),
    limit(30)
  ]);

  const [activeTab, setActiveTab] = useState<typeof TABS[number]>('Push Notifications');
  const [composeTitle, setComposeTitle] = useState('');
  const [composeMessage, setComposeMessage] = useState('');
  const [composeAudience, setComposeAudience] = useState('all');
  const [actionLoading, setActionLoading] = useState(false);

  const currentType = activeTab === 'Push Notifications' ? 'push' : activeTab === 'SMS Broadcast' ? 'sms' : 'email';
  const filteredBroadcasts = broadcasts.filter((b) => b.type === currentType);

  const handleSend = async () => {
    if (!composeTitle || !composeMessage) {
      alert('Please enter both title and message.');
      return;
    }

    setActionLoading(true);
    try {
      // 1. Resolve recipients
      let recipients: any[] = [];
      if (composeAudience === 'all') {
        recipients = await getUsers();
      } else if (composeAudience === 'job_seekers') {
        recipients = await getUsers({ role: 'job_seeker' });
      } else if (composeAudience === 'employers') {
        const employers = await getUsers({ role: 'employer' });
        const businessOwners = await getUsers({ role: 'business_owner' });
        recipients = [...employers, ...businessOwners];
      }

      // Remove duplicate users just in case
      const recipientIds = Array.from(new Set(recipients.map((r) => r.id)));

      // 2. Create the notification documents for each recipient
      await Promise.all(
        recipientIds.map((userId) =>
          createNotification({
            userId,
            type: 'broadcast',
            title: composeTitle,
            message: composeMessage,
            actionUrl: '/seeker/notifications',
          })
        )
      );

      // 3. Create the broadcast history document
      await createDocument('broadcasts', {
        title: composeTitle,
        message: composeMessage,
        type: currentType,
        audience: AUDIENCE_OPTIONS.find((o) => o.value === composeAudience)?.label || 'All Users',
        status: 'sent',
        stats: {
          sent: recipientIds.length,
          delivered: recipientIds.length,
          opened: Math.round(recipientIds.length * 0.65), // simulated engagement rate
        },
      });

      // Clear compose fields
      setComposeTitle('');
      setComposeMessage('');
      alert('Broadcast sent successfully!');
    } catch (err) {
      console.error('Send broadcast error:', err);
      alert('Failed to send broadcast.');
    } finally {
      setActionLoading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">Notification Management</h1>
          <p className="text-sm text-gray-400 mt-1">Broadcast messages to users via push, SMS, or email</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 p-1 rounded-xl bg-white/[0.03] border border-white/[0.06] overflow-x-auto no-scrollbar">
        {TABS.map((tab) => {
          const typeKey = tab === 'Push Notifications' ? 'push' : tab === 'SMS Broadcast' ? 'sms' : 'email';
          const cfg = TYPE_CONFIG[typeKey];
          const Icon = cfg.icon;
          return (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${activeTab === tab
                ? 'bg-violet-500/20 text-violet-400 border border-violet-500/30'
                : 'text-gray-400 hover:text-white hover:bg-white/[0.04]'
                }`}
            >
              <Icon size={14} />
              {tab}
            </button>
          );
        })}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        {/* Compose Form */}
        <div className="xl:col-span-1">
          <div className="glass-card rounded-2xl p-5">
            <div className="flex items-center gap-2 mb-5">
              <Send size={16} className="text-violet-400" />
              <h2 className="text-sm font-semibold text-white">Compose Message</h2>
            </div>

            <div className="space-y-4">
              {/* Title */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Title</label>
                <input
                  type="text"
                  value={composeTitle}
                  onChange={(e) => setComposeTitle(e.target.value)}
                  placeholder="Notification title..."
                  className="search-input w-full px-3.5 py-2.5 text-sm"
                />
              </div>

              {/* Message */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Message Body</label>
                <textarea
                  value={composeMessage}
                  onChange={(e) => setComposeMessage(e.target.value)}
                  placeholder="Write your message..."
                  rows={5}
                  className="search-input w-full px-3.5 py-2.5 text-sm resize-none"
                />
              </div>

              {/* Target Audience */}
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Target Audience</label>
                <div className="relative">
                  <select
                    value={composeAudience}
                    onChange={(e) => setComposeAudience(e.target.value)}
                    className="appearance-none w-full pl-3.5 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
                  >
                    {AUDIENCE_OPTIONS.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                  <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
                </div>
              </div>

              {/* Send Button */}
              <button
                disabled={actionLoading}
                onClick={handleSend}
                className="btn-gradient w-full flex items-center justify-center gap-2 px-5 py-3 rounded-xl text-sm relative z-0 disabled:opacity-50"
              >
                {actionLoading ? (
                  <Loader2 size={16} className="relative z-10 animate-spin" />
                ) : (
                  <>
                    <Send size={16} className="relative z-10" />
                    <span className="relative z-10">Send Now</span>
                  </>
                )}
              </button>
            </div>
          </div>
        </div>

        {/* Recent Notifications */}
        <div className="xl:col-span-2">
          <div className="glass-card rounded-2xl overflow-hidden">
            <div className="px-5 py-4 border-b border-white/[0.06]">
              <h2 className="text-sm font-semibold text-white">Recent {activeTab}</h2>
              <p className="text-[10px] text-gray-500 mt-0.5">Delivery and engagement statistics</p>
            </div>

            {loading ? (
              <div className="flex justify-center py-20">
                <Loader2 size={36} className="text-violet-400 animate-spin" />
              </div>
            ) : filteredBroadcasts.length > 0 ? (
              <div className="divide-y divide-white/[0.04]">
                {filteredBroadcasts.map((notif) => {
                  const typeCfg = TYPE_CONFIG[notif.type];
                  const TypeIcon = typeCfg.icon;
                  const stats = notif.stats || { sent: 0, delivered: 0, opened: 0 };
                  const deliveryRate = stats.sent > 0 ? ((stats.delivered / stats.sent) * 100).toFixed(1) : '0';
                  const openRate = stats.sent > 0 ? ((stats.opened / stats.sent) * 100).toFixed(1) + '%' : 'N/A';

                  return (
                    <div key={notif.id} className="px-5 py-4 hover:bg-white/[0.02] transition-colors">
                      <div className="flex items-start gap-3">
                        <div className={`w-9 h-9 rounded-xl ${typeCfg.bg} flex items-center justify-center flex-shrink-0 mt-0.5`}>
                          <TypeIcon size={16} className={typeCfg.text} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <p className="text-sm font-semibold text-white truncate">{notif.title}</p>
                            <span className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-emerald-500/10 text-emerald-400 text-[9px] font-bold flex-shrink-0">
                              <CheckCircle size={9} /> Sent
                            </span>
                          </div>
                          <p className="text-xs text-gray-400 line-clamp-2 mb-2">{notif.message}</p>
                          <div className="flex items-center flex-wrap gap-x-4 gap-y-1">
                            <span className="text-[10px] text-gray-500 flex items-center gap-1">
                              <Users size={10} /> {notif.audience}
                            </span>
                            <span className="text-[10px] text-gray-500 flex items-center gap-1">
                              <Clock size={10} /> {notif.sentAt ? new Date(notif.sentAt).toLocaleString('en-IN') : 'Recent'}
                            </span>
                          </div>
                          {/* Delivery Stats */}
                          <div className="flex items-center gap-4 mt-3 p-2.5 rounded-lg bg-white/[0.02] border border-white/[0.04]">
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-white">{stats.sent.toLocaleString()}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Sent</p>
                            </div>
                            <div className="w-px h-8 bg-white/[0.06]" />
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-emerald-400">{stats.delivered.toLocaleString()}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Delivered ({deliveryRate}%)</p>
                            </div>
                            <div className="w-px h-8 bg-white/[0.06]" />
                            <div className="text-center flex-1">
                              <p className="text-sm font-bold text-cyan-400">{stats.opened > 0 ? stats.opened.toLocaleString() : '—'}</p>
                              <p className="text-[9px] text-gray-500 uppercase">Opened ({openRate})</p>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center py-16">
                <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
                  <Bell size={28} className="text-gray-600" />
                </div>
                <p className="text-sm font-medium text-gray-400">No {activeTab.toLowerCase()} sent yet</p>
                <p className="text-xs text-gray-600 mt-1">Compose your first message using the form</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import {
  Star, Search, ChevronDown, CheckCircle, XCircle,
  Flag, Trash2, MessageSquare, Clock, AlertTriangle,
  ThumbsUp, ThumbsDown, Building2, Briefcase, Wrench, Loader2
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { updateDocument, deleteDocument } from '@/lib/firebase/firestoreService';

// ===== TYPES =====
interface ReviewDoc {
  id: string;
  reviewerName: string;
  rating: number;
  text: string;
  targetName: string;
  targetType: 'business' | 'employer' | 'service';
  createdAt?: any;
  status?: 'approved' | 'pending' | 'flagged';
  helpful?: number;
  unhelpful?: number;
  flagReason?: string;
}

// ===== CONSTANTS =====
const STATUS_CONFIG: Record<string, { label: string; bg: string; text: string }> = {
  approved: { label: 'Approved', bg: 'bg-emerald-500/15', text: 'text-emerald-400' },
  pending: { label: 'Pending', bg: 'bg-amber-500/15', text: 'text-amber-400' },
  flagged: { label: 'Flagged', bg: 'bg-rose-500/15', text: 'text-rose-400' },
};

const TARGET_CONFIG: Record<string, { label: string; icon: typeof Building2; bg: string; text: string }> = {
  business: { label: 'Business', icon: Building2, bg: 'bg-cyan-500/10', text: 'text-cyan-400' },
  employer: { label: 'Employer', icon: Briefcase, bg: 'bg-violet-500/10', text: 'text-violet-400' },
  service: { label: 'Service', icon: Wrench, bg: 'bg-amber-500/10', text: 'text-amber-400' },
};

const TABS = ['All', 'Pending', 'Flagged', 'Business Reviews', 'Employer Reviews', 'Service Reviews'] as const;

function StarRating({ rating }: { rating: number }) {
  return (
    <div className="flex items-center gap-0.5">
      {[1, 2, 3, 4, 5].map((i) => (
        <Star
          key={i}
          size={14}
          className={i <= rating ? 'text-amber-400' : 'text-gray-700'}
          fill={i <= rating ? 'currentColor' : 'none'}
        />
      ))}
    </div>
  );
}

export default function ReviewsPage() {
  const { data: reviews, loading } = useCollection<ReviewDoc>('reviews');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<typeof TABS[number]>('All');
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const getInitials = (name?: string) => {
    return name ? name.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2) : 'RE';
  };

  const filteredReviews = reviews.filter((review) => {
    const reviewerName = review.reviewerName || 'Anonymous';
    const targetName = review.targetName || 'Unknown';
    const text = review.text || '';
    const matchSearch = reviewerName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      targetName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      text.toLowerCase().includes(searchQuery.toLowerCase());

    const reviewStatus = review.status || 'pending';
    const targetType = review.targetType || 'business';

    const matchTab = activeTab === 'All' ||
      (activeTab === 'Pending' && reviewStatus === 'pending') ||
      (activeTab === 'Flagged' && reviewStatus === 'flagged') ||
      (activeTab === 'Business Reviews' && targetType === 'business') ||
      (activeTab === 'Employer Reviews' && targetType === 'employer') ||
      (activeTab === 'Service Reviews' && targetType === 'service');

    return matchSearch && matchTab;
  });

  const handleApprove = async (id: string) => {
    setActionLoading(id);
    try {
      await updateDocument('reviews', id, { status: 'approved' });
    } catch (err) {
      console.error('Approve review error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleFlag = async (id: string) => {
    const reason = window.prompt('Enter flag/report reason:');
    if (reason === null) return;
    setActionLoading(id);
    try {
      await updateDocument('reviews', id, { status: 'flagged', flagReason: reason });
    } catch (err) {
      console.error('Flag review error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm('Are you sure you want to delete this review?')) return;
    setActionLoading(id);
    try {
      await deleteDocument('reviews', id);
    } catch (err) {
      console.error('Delete review error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Dynamic metrics
  const totalCount = reviews.length;
  const pendingCount = reviews.filter((r) => (r.status || 'pending') === 'pending').length;
  const flaggedCount = reviews.filter((r) => r.status === 'flagged').length;
  const avgRating = totalCount > 0 ? (reviews.reduce((sum, r) => sum + (r.rating || 0), 0) / totalCount).toFixed(1) : '0.0';

  const stats = [
    { label: 'Total Reviews', value: totalCount, icon: MessageSquare, color: 'violet' },
    { label: 'Pending Moderation', value: pendingCount, icon: Clock, color: 'amber' },
    { label: 'Flagged', value: flaggedCount, icon: Flag, color: 'rose' },
    { label: 'Average Rating', value: avgRating, icon: Star, color: 'cyan', isStar: true },
  ];

  const statColorMap: Record<string, { bg: string; text: string }> = {
    violet: { bg: 'bg-violet-500/15', text: 'text-violet-400' },
    amber: { bg: 'bg-amber-500/15', text: 'text-amber-400' },
    rose: { bg: 'bg-rose-500/15', text: 'text-rose-400' },
    cyan: { bg: 'bg-cyan-500/15', text: 'text-cyan-400' },
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">Reviews & Ratings</h1>
          <p className="text-sm text-gray-400 mt-1">Moderate reviews and manage platform ratings</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat) => {
          const colors = statColorMap[stat.color];
          const Icon = stat.icon;
          return (
            <div key={stat.label} className="glass-card rounded-2xl p-4 hover:border-white/[0.15] transition-all">
              <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-xl ${colors.bg} flex items-center justify-center`}>
                  <Icon size={18} className={colors.text} fill={stat.isStar ? 'currentColor' : 'none'} />
                </div>
                <div>
                  <p className="text-xl font-bold text-white font-outfit">{stat.value}</p>
                  <p className="text-xs text-gray-500">{stat.label}</p>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 p-1 rounded-xl bg-white/[0.03] border border-white/[0.06] overflow-x-auto no-scrollbar">
        {TABS.map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-2 rounded-lg text-xs font-semibold whitespace-nowrap transition-all ${activeTab === tab
              ? 'bg-violet-500/20 text-violet-400 border border-violet-500/30'
              : 'text-gray-400 hover:text-white hover:bg-white/[0.04]'
              }`}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* Search */}
      <div className="relative">
        <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
        <input
          type="text"
          placeholder="Search reviews..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="search-input w-full pl-10 pr-4 py-2.5 text-sm"
        />
      </div>

      {/* Review Cards */}
      {loading ? (
        <div className="flex flex-col items-center justify-center py-20">
          <Loader2 size={36} className="text-violet-400 animate-spin mb-4" />
          <p className="text-sm text-gray-400">Loading reviews from Firestore...</p>
        </div>
      ) : filteredReviews.length > 0 ? (
        <div className="space-y-4">
          {filteredReviews.map((review) => {
            const reviewStatus = review.status || 'pending';
            const statusCfg = STATUS_CONFIG[reviewStatus];
            const targetType = review.targetType || 'business';
            const targetCfg = TARGET_CONFIG[targetType] || TARGET_CONFIG.business;
            const TargetIcon = targetCfg.icon;
            const initials = getInitials(review.reviewerName);

            return (
              <div
                key={review.id}
                className={`glass-card rounded-2xl p-5 hover:border-white/[0.15] transition-all ${reviewStatus === 'flagged' ? 'border-rose-500/25' : ''
                  }`}
              >
                {/* Review Header */}
                <div className="flex items-start justify-between gap-4 mb-3">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center flex-shrink-0">
                      <span className="text-white text-xs font-bold">{initials}</span>
                    </div>
                    <div>
                      <p className="text-sm font-semibold text-white">{review.reviewerName || 'Anonymous'}</p>
                      <div className="flex items-center gap-2 mt-0.5">
                        <StarRating rating={review.rating || 5} />
                        <span className="text-xs text-gray-500">·</span>
                        <span className="text-xs text-gray-500">
                          {review.createdAt ? new Date(review.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'Recent'}
                        </span>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 flex-shrink-0">
                    <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusCfg.bg} ${statusCfg.text}`}>
                      {reviewStatus === 'flagged' && <AlertTriangle size={10} className="mr-1" />}
                      {statusCfg.label}
                    </span>
                    <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-bold ${targetCfg.bg} ${targetCfg.text}`}>
                      <TargetIcon size={10} />
                      {targetCfg.label}
                    </span>
                  </div>
                </div>

                {/* Target */}
                <div className="flex items-center gap-1.5 mb-2">
                  <span className="text-xs text-gray-500">Reviewing:</span>
                  <span className="text-xs font-semibold text-white">{review.targetName || 'Unknown Target'}</span>
                </div>

                {/* Review Text */}
                <p className="text-sm text-gray-300 leading-relaxed mb-3">{review.text}</p>

                {/* Flag Reason */}
                {review.flagReason && (
                  <div className="flex items-start gap-2 p-3 rounded-xl bg-rose-500/5 border border-rose-500/15 mb-3">
                    <AlertTriangle size={14} className="text-rose-400 mt-0.5 flex-shrink-0" />
                    <p className="text-xs text-rose-300">{review.flagReason}</p>
                  </div>
                )}

                {/* Footer */}
                <div className="flex items-center justify-between pt-3 border-t border-white/[0.06]">
                  <div className="flex items-center gap-4">
                    <span className="flex items-center gap-1 text-xs text-gray-500">
                      <ThumbsUp size={12} /> {review.helpful || 0}
                    </span>
                    <span className="flex items-center gap-1 text-xs text-gray-500">
                      <ThumbsDown size={12} /> {review.unhelpful || 0}
                    </span>
                  </div>
                  <div className="flex items-center gap-1">
                    {actionLoading === review.id ? (
                      <Loader2 size={16} className="text-violet-400 animate-spin" />
                    ) : (
                      <>
                        {reviewStatus === 'pending' && (
                          <>
                            <button
                              onClick={() => handleApprove(review.id)}
                              className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-emerald-500/10 text-emerald-400 text-xs font-medium hover:bg-emerald-500/20 transition-colors"
                            >
                              <CheckCircle size={13} /> Approve
                            </button>
                            <button
                              onClick={() => handleDelete(review.id)}
                              className="flex items-center gap-1 px-3 py-1.5 rounded-lg bg-rose-500/10 text-rose-400 text-xs font-medium hover:bg-rose-500/20 transition-colors"
                            >
                              <XCircle size={13} /> Reject
                            </button>
                          </>
                        )}
                        <button
                          onClick={() => handleFlag(review.id)}
                          className="p-2 rounded-lg text-gray-400 hover:text-amber-400 hover:bg-amber-500/10 transition-all"
                          title="Flag Review"
                        >
                          <Flag size={14} />
                        </button>
                        <button
                          onClick={() => handleDelete(review.id)}
                          className="p-2 rounded-lg text-gray-400 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
                          title="Delete Review"
                        >
                          <Trash2 size={14} />
                        </button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="glass-card rounded-2xl flex flex-col items-center justify-center py-16">
          <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
            <MessageSquare size={28} className="text-gray-600" />
          </div>
          <p className="text-sm font-medium text-gray-400">No reviews found</p>
          <p className="text-xs text-gray-600 mt-1">Try adjusting your filters</p>
        </div>
      )}
    </div>
  );
}

