          />
        </div>
        <div className="flex gap-2">
          <div className="relative">
            <select value={planFilter} onChange={(e) => setPlanFilter(e.target.value)} className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer">
              <option value="all">All Plans</option>
              <option value="free">Free</option>
              <option value="basic">Basic</option>
              <option value="premium">Premium</option>
              <option value="enterprise">Enterprise</option>
            </select>
            <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
          </div>
          <div className="relative">
            <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer">
              <option value="all">All Status</option>
              <option value="active">Active</option>
              <option value="expired">Expired</option>
              <option value="cancelled">Cancelled</option>
            </select>
            <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
          </div>
        </div>
      </div>

      {/* Subscribers Table */}
      <div className="glass-card rounded-2xl overflow-hidden">
        <div className="px-5 py-4 border-b border-white/[0.06]">
          <h2 className="text-sm font-semibold text-white">Subscribers</h2>
        </div>
        <div className="overflow-x-auto">
          {subsLoading ? (
            <div className="flex flex-col items-center justify-center py-20">
              <Loader2 size={36} className="text-violet-400 animate-spin mb-4" />
              <p className="text-sm text-gray-400">Loading subscribers...</p>
            </div>
          ) : (
            <table className="w-full">
              <thead>
                <tr className="border-b border-white/[0.06]">
                  <th className="text-left px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Business</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Plan</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden sm:table-cell">Amount</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden lg:table-cell">Period</th>
                  <th className="text-center px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden md:table-cell">Auto-Renew</th>
                  <th className="text-right px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/[0.04]">
                {filteredSubs.map((sub) => {
                  const subPlan = sub.plan || 'free';
                  const planCfg = PLAN_CONFIG[subPlan] || PLAN_CONFIG.free;
                  const subStatus = sub.status || 'active';
                  const statusCfg = STATUS_CONFIG[subStatus] || STATUS_CONFIG.active;
                  const name = sub.businessName || sub.companyName || 'Unknown';
                  const initials = getInitials(name);
                  const initialBg = getInitialColor(name);

                  return (
                    <tr key={sub.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-5 py-3.5">
                        <div className="flex items-center gap-3">
                          <div className={`w-9 h-9 rounded-xl bg-gradient-to-br ${initialBg} flex items-center justify-center flex-shrink-0`}>
                            <span className="text-white text-xs font-bold">{initials}</span>
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-white truncate">{name}</p>
                            <p className="text-[10px] text-gray-500">{sub.paymentMethod || '—'}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${planCfg.bg} ${planCfg.text}`}>
                          {planCfg.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden sm:table-cell">
                        <span className="text-sm text-white font-medium">₹{sub.amount || 0}</span>
                        <span className="text-xs text-gray-600">/mo</span>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusCfg.bg} ${statusCfg.text}`}>
                          <span className={`w-1.5 h-1.5 rounded-full ${statusCfg.dot}`} />
                          {statusCfg.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden lg:table-cell">
                        <p className="text-xs text-gray-400">
                          {sub.startDate ? new Date(sub.startDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: '2-digit' }) : 'N/A'}
                          <span className="text-gray-600"> → </span>
                          {sub.endDate ? new Date(sub.endDate).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: '2-digit' }) : 'Forever'}
                        </p>
                      </td>
                      <td className="px-4 py-3.5 hidden md:table-cell text-center">
                        <span className={`text-xs ${sub.autoRenew ? 'text-emerald-400' : 'text-gray-500'}`}>
                          {sub.autoRenew ? 'Yes' : 'No'}
                        </span>
                      </td>
                      <td className="px-5 py-3.5">
                        <div className="flex items-center justify-end gap-1">
                          <button className="p-2 rounded-lg text-gray-400 hover:text-white hover:bg-white/[0.06] transition-all" title="View">
                            <Eye size={15} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>

        {!subsLoading && filteredSubs.length === 0 && (
          <div className="flex flex-col items-center justify-center py-16">
            <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
              <CreditCard size={28} className="text-gray-600" />
            </div>
            <p className="text-sm font-medium text-gray-400">No subscriptions found</p>
            <p className="text-xs text-gray-600 mt-1">Try adjusting your filters</p>
          </div>
        )}
      </div>

      {/* Payment History */}
      <div className="glass-card rounded-2xl overflow-hidden">
        <div className="px-5 py-4 border-b border-white/[0.06]">
          <h2 className="text-sm font-semibold text-white">Recent Payments</h2>
        </div>
        {paymentsLoading ? (
          <div className="p-5 flex justify-center">
            <Loader2 size={24} className="text-violet-400 animate-spin" />
          </div>
        ) : payments.length === 0 ? (
          <div className="p-8 text-center text-gray-500 text-xs">
            No payments recorded yet. Active subscription MRR will count towards total estimates.
          </div>
        ) : (
          <div className="divide-y divide-white/[0.04]">
            {payments.map((payment) => (
              <div key={payment.id} className="flex items-center gap-4 px-5 py-3.5 hover:bg-white/[0.02] transition-colors">
                <div className="w-9 h-9 rounded-xl bg-emerald-500/10 flex items-center justify-center flex-shrink-0">
                  <ArrowUpRight size={16} className="text-emerald-400" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-white truncate">{payment.businessName || payment.companyName || 'Business'}</p>
                  <p className="text-[10px] text-gray-500">{payment.plan || 'Plan'} · {payment.paymentMethod || 'UPI'}</p>
                </div>
                <div className="text-right flex-shrink-0">
                  <p className="text-sm font-bold text-emerald-400">₹{payment.amount}</p>
                  <p className="text-[10px] text-gray-500">
                    {payment.createdAt ? new Date(payment.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' }) : 'Recent'}
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import {
  Users, Search, Filter, ChevronDown, ChevronLeft, ChevronRight,
  Eye, ShieldCheck, Ban, Trash2, UserPlus, CheckCircle, XCircle,
  MoreHorizontal, Download, Mail, UserCheck, AlertCircle, Clock, Loader2
} from 'lucide-react';
import { useCollection } from '@/hooks/useFirestore';
import { useAuth } from '@/hooks/useAuth';
import {
  updateDocument,
  deleteDocument,
  verifyUser,
  updateUserRole,
} from '@/lib/firebase/firestoreService';

// ===== TYPES =====
interface UserDoc {
  id: string;
  displayName?: string;
  name?: string; // fallback
  email: string;
  role: UserRole;
  district?: string;
  status?: 'active' | 'suspended' | 'pending';
  isVerified?: boolean;
  createdAt?: any;
  phone?: string;
}

type UserRole = 'job_seeker' | 'employer' | 'business_owner' | 'admin' | 'super_admin' | 'supplier' | 'service_provider';

// ===== CONSTANTS =====
const ROLE_CONFIG: Record<UserRole, { label: string; bg: string; text: string }> = {
  job_seeker: { label: 'Job Seeker', bg: 'bg-cyan-500/15', text: 'text-cyan-400' },
  employer: { label: 'Employer', bg: 'bg-violet-500/15', text: 'text-violet-400' },
  business_owner: { label: 'Business Owner', bg: 'bg-amber-500/15', text: 'text-amber-400' },
  admin: { label: 'Admin', bg: 'bg-rose-500/15', text: 'text-rose-400' },
  super_admin: { label: 'Super Admin', bg: 'bg-purple-500/15', text: 'text-purple-400' },
  supplier: { label: 'Supplier', bg: 'bg-emerald-500/15', text: 'text-emerald-400' },
  service_provider: { label: 'Service Provider', bg: 'bg-blue-500/15', text: 'text-blue-400' },
};

const STATUS_CONFIG: Record<string, { label: string; bg: string; text: string; dot: string }> = {
  active: { label: 'Active', bg: 'bg-emerald-500/15', text: 'text-emerald-400', dot: 'bg-emerald-400' },
  suspended: { label: 'Suspended', bg: 'bg-rose-500/15', text: 'text-rose-400', dot: 'bg-rose-400' },
  pending: { label: 'Pending', bg: 'bg-amber-500/15', text: 'text-amber-400', dot: 'bg-amber-400' },
};

const DISTRICTS = ['All Districts', 'Theni', 'Madurai', 'Dindigul', 'Chennai', 'Coimbatore', 'Trichy', 'Salem', 'Tirunelveli', 'Erode', 'Vellore'];

const colorMap: Record<string, { bg: string; text: string; iconBg: string }> = {
  violet: { bg: 'bg-violet-500/10', text: 'text-violet-400', iconBg: 'bg-violet-500/15' },
  emerald: { bg: 'bg-emerald-500/10', text: 'text-emerald-400', iconBg: 'bg-emerald-500/15' },
  rose: { bg: 'bg-rose-500/10', text: 'text-rose-400', iconBg: 'bg-rose-500/15' },
  amber: { bg: 'bg-amber-500/10', text: 'text-amber-400', iconBg: 'bg-amber-500/15' },
};

export default function UsersPage() {
  const { user: currentUser } = useAuth();
  const { data: users, loading, error } = useCollection<UserDoc>('users');
  const [searchQuery, setSearchQuery] = useState('');
  const [roleFilter, setRoleFilter] = useState('all');
  const [statusFilter, setStatusFilter] = useState('all');
  const [districtFilter, setDistrictFilter] = useState('All Districts');
  const [selectedUsers, setSelectedUsers] = useState<string[]>([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [actionLoading, setActionLoading] = useState<string | null>(null);

  const getInitials = (name?: string, email?: string) => {
    const text = name || email || 'User';
    return text.split(' ').map((n) => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const filteredUsers = users.filter((user) => {
    const nameStr = user.displayName || user.name || '';
    const emailStr = user.email || '';
    const matchSearch = nameStr.toLowerCase().includes(searchQuery.toLowerCase()) ||
      emailStr.toLowerCase().includes(searchQuery.toLowerCase());
    const matchRole = roleFilter === 'all' || user.role === roleFilter;

    const status = user.status || 'active';
    const matchStatus = statusFilter === 'all' || status === statusFilter;

    const district = user.district || 'Theni';
    const matchDistrict = districtFilter === 'All Districts' || district === districtFilter;

    return matchSearch && matchRole && matchStatus && matchDistrict;
  });

  const toggleSelectAll = () => {
    if (selectedUsers.length === filteredUsers.length) {
      setSelectedUsers([]);
    } else {
      setSelectedUsers(filteredUsers.map((u) => u.id));
    }
  };

  const toggleSelect = (id: string) => {
    setSelectedUsers((prev) =>
      prev.includes(id) ? prev.filter((uid) => uid !== id) : [...prev, id]
    );
  };

  const handleVerify = async (userId: string) => {
    setActionLoading(userId);
    try {
      await verifyUser(userId, currentUser?.uid || 'admin');
    } catch (err) {
      console.error('Verify user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleSuspendToggle = async (userId: string, currentStatus?: string) => {
    setActionLoading(userId);
    try {
      const newStatus = currentStatus === 'suspended' ? 'active' : 'suspended';
      await updateDocument('users', userId, { status: newStatus });
    } catch (err) {
      console.error('Suspend user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleDelete = async (userId: string) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    setActionLoading(userId);
    try {
      await deleteDocument('users', userId);
      setSelectedUsers(prev => prev.filter(id => id !== userId));
    } catch (err) {
      console.error('Delete user error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Bulk Actions
  const handleBulkVerify = async () => {
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => verifyUser(id, currentUser?.uid || 'admin')));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk verify error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleBulkSuspend = async () => {
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => updateDocument('users', id, { status: 'suspended' })));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk suspend error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  const handleBulkDelete = async () => {
    if (!window.confirm(`Are you sure you want to delete ${selectedUsers.length} users?`)) return;
    setActionLoading('bulk');
    try {
      await Promise.all(selectedUsers.map((id) => deleteDocument('users', id)));
      setSelectedUsers([]);
    } catch (err) {
      console.error('Bulk delete error:', err);
    } finally {
      setActionLoading(null);
    }
  };

  // Dynamic statistics
  const totalUsers = users.length;
  const activeUsers = users.filter((u) => (u.status || 'active') === 'active').length;
  const suspendedUsers = users.filter((u) => u.status === 'suspended').length;
  const pendingUsers = users.filter((u) => !u.isVerified).length;

  const userStats = [
    { label: 'Total Users', value: totalUsers, icon: Users, color: 'violet', trend: 'Live' },
    { label: 'Active Users', value: activeUsers, icon: UserCheck, color: 'emerald', trend: 'Live' },
    { label: 'Suspended', value: suspendedUsers, icon: Ban, color: 'rose', trend: 'Live' },
    { label: 'Pending Verification', value: pendingUsers, icon: Clock, color: 'amber', trend: 'Live' },
  ];

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Page Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white font-outfit">User Management</h1>
          <p className="text-sm text-gray-400 mt-1">Manage all platform users, roles, and permissions</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-gray-300 hover:bg-white/[0.08] hover:border-white/[0.15] transition-all">
            <Download size={16} />
            <span className="hidden sm:inline">Export</span>
          </button>
        </div>
      </div>

      {/* Stats Mini-Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {userStats.map((stat) => {
          const colors = colorMap[stat.color];
          const Icon = stat.icon;
          return (
            <div key={stat.label} className="glass-card rounded-2xl p-4 hover:border-white/[0.15] transition-all">
              <div className="flex items-center justify-between">
                <div className={`w-10 h-10 rounded-xl ${colors.iconBg} flex items-center justify-center`}>
                  <Icon size={18} className={colors.text} />
                </div>
                <span className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-white/[0.06] text-gray-400">
                  {stat.trend}
                </span>
              </div>
              <p className="text-xl font-bold text-white mt-3 font-outfit">{stat.value}</p>
              <p className="text-xs text-gray-500 mt-0.5">{stat.label}</p>
            </div>
          );
        })}
      </div>

      {/* Search & Filters */}
      <div className="glass-card rounded-2xl p-4">
        <div className="flex flex-col lg:flex-row gap-3">
          {/* Search */}
          <div className="relative flex-1">
            <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
            <input
              type="text"
              placeholder="Search users by name or email..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="search-input w-full pl-10 pr-4 py-2.5 text-sm"
            />
          </div>
          {/* Filters */}
          <div className="flex flex-wrap gap-2">
            <div className="relative">
              <select
                value={roleFilter}
                onChange={(e) => setRoleFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                <option value="all">All Roles</option>
                <option value="job_seeker">Job Seeker</option>
                <option value="employer">Employer</option>
                <option value="business_owner">Business Owner</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
                <option value="supplier">Supplier</option>
                <option value="service_provider">Service Provider</option>
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
            <div className="relative">
              <select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                <option value="all">All Status</option>
                <option value="active">Active</option>
                <option value="suspended">Suspended</option>
                <option value="pending">Pending</option>
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
            <div className="relative">
              <select
                value={districtFilter}
                onChange={(e) => setDistrictFilter(e.target.value)}
                className="appearance-none pl-3 pr-8 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.1] text-sm text-gray-300 outline-none focus:border-violet-500/40 transition-all cursor-pointer"
              >
                {DISTRICTS.map((d) => (
                  <option key={d} value={d}>{d}</option>
                ))}
              </select>
              <ChevronDown size={14} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-gray-500 pointer-events-none" />
            </div>
          </div>
        </div>
      </div>

      {/* Bulk Action Bar */}
      {selectedUsers.length > 0 && (
        <div className="glass-card rounded-2xl p-3 flex items-center justify-between border-violet-500/20 animate-fade-in-up">
          <div className="flex items-center gap-3">
            <span className="text-sm text-white font-medium">{selectedUsers.length} user(s) selected</span>
          </div>
          <div className="flex items-center gap-2">
            {actionLoading === 'bulk' ? (
              <Loader2 size={16} className="text-violet-400 animate-spin mr-2" />
            ) : (
              <>
                <button
                  onClick={handleBulkVerify}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-500/10 text-emerald-400 text-xs font-medium hover:bg-emerald-500/20 transition-colors"
                >
                  <ShieldCheck size={14} /> Verify
                </button>
                <button
                  onClick={handleBulkSuspend}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-amber-500/10 text-amber-400 text-xs font-medium hover:bg-amber-500/20 transition-colors"
                >
                  <Ban size={14} /> Suspend
                </button>
                <button
                  onClick={handleBulkDelete}
                  className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-rose-500/10 text-rose-400 text-xs font-medium hover:bg-rose-500/20 transition-colors"
                >
                  <Trash2 size={14} /> Delete
                </button>
              </>
            )}
          </div>
        </div>
      )}

      {/* Users Table */}
      <div className="glass-card rounded-2xl overflow-hidden">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <Loader2 size={36} className="text-violet-400 animate-spin mb-4" />
            <p className="text-sm text-gray-400">Loading users from Firestore...</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-white/[0.06]">
                  <th className="text-left px-5 py-3.5 w-12">
                    <input
                      type="checkbox"
                      checked={selectedUsers.length === filteredUsers.length && filteredUsers.length > 0}
                      onChange={toggleSelectAll}
                      className="w-4 h-4 rounded border-white/20 bg-white/[0.04] accent-violet-500"
                    />
                  </th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">User</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Role</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden lg:table-cell">District</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Status</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden md:table-cell">Verified</th>
                  <th className="text-left px-4 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider hidden xl:table-cell">Join Date</th>
                  <th className="text-right px-5 py-3.5 text-xs font-semibold text-gray-400 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/[0.04]">
                {filteredUsers.map((user) => {
                  const roleConfig = ROLE_CONFIG[user.role] || { label: user.role, bg: 'bg-gray-500/15', text: 'text-gray-400' };
                  const userStatus = user.status || 'active';
                  const statusConfig = STATUS_CONFIG[userStatus];
                  return (
                    <tr key={user.id} className="hover:bg-white/[0.02] transition-colors">
                      <td className="px-5 py-3.5">
                        <input
                          type="checkbox"
                          checked={selectedUsers.includes(user.id)}
                          onChange={() => toggleSelect(user.id)}
                          className="w-4 h-4 rounded border-white/20 bg-white/[0.04] accent-violet-500"
                        />
                      </td>
                      <td className="px-4 py-3.5">
                        <div className="flex items-center gap-3">
                          <div className="w-9 h-9 rounded-full bg-gradient-to-br from-violet-500 to-cyan-500 flex items-center justify-center flex-shrink-0">
                            <span className="text-white text-xs font-bold">{getInitials(user.displayName || user.name, user.email)}</span>
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-medium text-white truncate">{user.displayName || user.name || 'Unnamed User'}</p>
                            <p className="text-xs text-gray-500 truncate">{user.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${roleConfig.bg} ${roleConfig.text}`}>
                          {roleConfig.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden lg:table-cell">
                        <span className="text-sm text-gray-300">{user.district || 'Theni'}</span>
                      </td>
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${statusConfig.bg} ${statusConfig.text}`}>
                          <span className={`w-1.5 h-1.5 rounded-full ${statusConfig.dot}`} />
                          {statusConfig.label}
                        </span>
                      </td>
                      <td className="px-4 py-3.5 hidden md:table-cell">
                        {user.isVerified ? (
                          <CheckCircle size={18} className="text-emerald-400" />
                        ) : (
                          <XCircle size={18} className="text-gray-600" />
                        )}
                      </td>
                      <td className="px-4 py-3.5 hidden xl:table-cell">
                        <span className="text-sm text-gray-400">
                          {user.createdAt ? new Date(user.createdAt).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }) : 'N/A'}
                        </span>
                      </td>
                      <td className="px-5 py-3.5">
                        <div className="flex items-center justify-end gap-1">
                          {actionLoading === user.id ? (
                            <Loader2 size={16} className="text-violet-400 animate-spin" />
                          ) : (
                            <>
                              {!user.isVerified && (
                                <button
                                  onClick={() => handleVerify(user.id)}
                                  className="p-2 rounded-lg text-gray-400 hover:text-emerald-400 hover:bg-emerald-500/10 transition-all"
                                  title="Verify User"
                                >
                                  <ShieldCheck size={15} />
                                </button>
                              )}
                              <button
                                onClick={() => handleSuspendToggle(user.id, userStatus)}
                                className={`p-2 rounded-lg text-gray-400 transition-all ${
                                  userStatus === 'suspended'
                                    ? 'hover:text-emerald-400 hover:bg-emerald-500/10'
                                    : 'hover:text-amber-400 hover:bg-amber-500/10'
                                }`}
                                title={userStatus === 'suspended' ? 'Activate User' : 'Suspend User'}
                              >
                                <Ban size={15} />
                              </button>
                              <button
                                onClick={() => handleDelete(user.id)}
                                className="p-2 rounded-lg text-gray-400 hover:text-rose-400 hover:bg-rose-500/10 transition-all"
                                title="Delete User"
                              >
                                <Trash2 size={15} />
                              </button>
                            </>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* Empty State */}
        {!loading && filteredUsers.length === 0 && (
          <div className="flex flex-col items-center justify-center py-16">
            <div className="w-16 h-16 rounded-2xl bg-white/[0.04] flex items-center justify-center mb-4">
              <Users size={28} className="text-gray-600" />
            </div>
            <p className="text-sm font-medium text-gray-400">No users found</p>
            <p className="text-xs text-gray-600 mt-1">Try adjusting your search or filters</p>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import Header from '@/components/navigation/Header';
import BottomNav from '@/components/navigation/BottomNav';
import {
  Search, MapPin, Filter, X, BadgeCheck, Star,
  Briefcase, SlidersHorizontal, ArrowRight, Building2, TrendingUp,
  Navigation, MessageCircle, Phone, Loader2
} from 'lucide-react';
import { collection, getDocs, query, where, orderBy } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';

const CATEGORIES = ['All', 'Agriculture', 'Construction', 'Education', 'Healthcare', 'IT & Software', 'Textiles', 'Manufacturing', 'Retail', 'Transport', 'Finance', 'Food & Beverage'];
const DISTRICTS = ['All', 'Theni', 'Madurai', 'Dindigul', 'Coimbatore', 'Salem', 'Chennai', 'Trichy'];

const SORT_OPTIONS = [
  { value: 'premium', label: 'Featured First' },
  { value: 'rating', label: 'Top Rated' },
  { value: 'jobs', label: 'Most Jobs' },
  { value: 'new', label: 'Newest' },
];

interface Business {
  id: string;
  slug: string;
  name: string;
  category: string;
  district: string;
  rating: number;
  reviews: number;
  jobs: number;
  isVerified: boolean;
  isPremium: boolean;
  tagline: string;
  logo: string;
  isNew: boolean;
  phone: string;
  whatsapp: string;
}

export default function BusinessesPage() {
  const [search, setSearch] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [selectedDistrict, setSelectedDistrict] = useState('All');
  const [showVerifiedOnly, setShowVerifiedOnly] = useState(false);
  const [sortBy, setSortBy] = useState('premium');
  const [showFilters, setShowFilters] = useState(false);
  const [businesses, setBusinesses] = useState<Business[]>([]);
  const [loading, setLoading] = useState(true);

  // Load businesses from Firestore
  useEffect(() => {
    async function loadBusinesses() {
      try {
        const q = query(collection(db, 'companies'), where('status', '==', 'approved'));
        const snapshot = await getDocs(q);
        const data = snapshot.docs.map(doc => {
          const d = doc.data();
          return {
            id: doc.id,
            slug: d.slug || doc.id,
            name: d.name || '',
            category: d.category || '',
            district: d.district || '',
            rating: d.rating || 0,
            reviews: d.reviewCount || 0,
            jobs: d.jobCount || 0,
            isVerified: d.isVerified || false,
            isPremium: d.isPremium || false,
            tagline: d.tagline || d.description?.substring(0, 80) || '',
            logo: d.name ? d.name.split(' ').map((w: string) => w[0]).join('').substring(0, 2).toUpperCase() : 'B',
            isNew: d.createdAt ? (Date.now() - d.createdAt?.toMillis?.() < 7 * 24 * 60 * 60 * 1000) : false,
            phone: d.phone || '',
            whatsapp: d.whatsapp || d.phone || '',
          } as Business;
        });
        setBusinesses(data);
      } catch (err) {
        console.error('Error loading businesses:', err);
      } finally {
        setLoading(false);
      }
    }
    loadBusinesses();
  }, []);

  const filtered = businesses
    .filter(b => {
      const q = search.toLowerCase();
      const matchSearch = !q || b.name.toLowerCase().includes(q) || b.tagline.toLowerCase().includes(q) || b.category.toLowerCase().includes(q);
      const matchCat = selectedCategory === 'All' || b.category === selectedCategory;
      const matchDist = selectedDistrict === 'All' || b.district === selectedDistrict;
      const matchVerified = !showVerifiedOnly || b.isVerified;
      return matchSearch && matchCat && matchDist && matchVerified;
    })
    .sort((a, b) => {
      if (sortBy === 'premium') return (b.isPremium ? 1 : 0) - (a.isPremium ? 1 : 0);
      if (sortBy === 'rating') return b.rating - a.rating;
      if (sortBy === 'jobs') return b.jobs - a.jobs;
      if (sortBy === 'new') return (b.isNew ? 1 : 0) - (a.isNew ? 1 : 0);
      return 0;
    });

  const activeFilters = (selectedCategory !== 'All' ? 1 : 0) + (selectedDistrict !== 'All' ? 1 : 0) + (showVerifiedOnly ? 1 : 0);

  return (
    <main className="min-h-screen bg-[#0a0a1a]">
      <Header />

      {/* Sticky Search */}
      <div className="sticky top-16 z-40 glass-nav border-b border-white/5 px-4 sm:px-6 py-3">
        <div className="max-w-5xl mx-auto flex flex-wrap gap-2">
          <div className="min-w-0 flex-[1_1_220px] flex items-center gap-2 search-input px-4 py-2.5">
            <Search size={15} className="text-gray-500 shrink-0" />
            <input value={search} onChange={e => setSearch(e.target.value)} type="text"
              placeholder="Search businesses, services, categories..."
              className="min-w-0 flex-1 bg-transparent text-sm text-white placeholder-gray-500 outline-none" />
            {search && <button onClick={() => setSearch('')}><X size={13} className="text-gray-500" /></button>}
          </div>
          <div className="min-w-0 flex flex-1 sm:flex-none items-center gap-2 search-input px-3 py-2.5">
            <MapPin size={14} className="text-violet-400 shrink-0" />
            <select value={selectedDistrict} onChange={e => setSelectedDistrict(e.target.value)}
              className="min-w-0 flex-1 sm:w-24 bg-transparent text-sm text-gray-300 outline-none pr-1">
              {DISTRICTS.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <button onClick={() => setShowFilters(!showFilters)}
            className={`flex flex-none items-center justify-center gap-2 px-4 py-2.5 rounded-2xl text-sm font-medium transition-all border
              ${showFilters || activeFilters > 0 ? 'bg-violet-500/20 border-violet-500/40 text-violet-300' : 'bg-white/5 border-white/10 text-gray-400'}`}>
            <SlidersHorizontal size={15} />
            <span className="hidden sm:inline">Filters</span>
            {activeFilters > 0 && <span className="w-5 h-5 rounded-full bg-violet-600 text-white text-[10px] font-bold flex items-center justify-center">{activeFilters}</span>}
          </button>
        </div>

        {showFilters && (
          <div className="max-w-5xl mx-auto mt-3 glass-card rounded-2xl p-4 border border-white/10">
            <div className="space-y-4">
              <div>
                <p className="text-xs font-semibold text-gray-400 mb-2">Category</p>
                <div className="flex flex-wrap gap-2">
                  {CATEGORIES.map(c => (
                    <button key={c} onClick={() => setSelectedCategory(c)}
                      className={`px-3 py-1.5 rounded-xl text-xs font-medium border transition-all
                        ${selectedCategory === c ? 'bg-violet-500/20 border-violet-500/50 text-violet-300' : 'bg-white/5 border-white/10 text-gray-400 hover:text-white'}`}>
                      {c}
                    </button>
                  ))}
                </div>
              </div>
              <label className="flex items-center gap-2 cursor-pointer">
                <div onClick={() => setShowVerifiedOnly(!showVerifiedOnly)}
                  className={`w-9 h-5 rounded-full relative transition-all ${showVerifiedOnly ? 'bg-violet-600' : 'bg-white/20'}`}>
                  <div className={`w-3.5 h-3.5 rounded-full bg-white absolute top-0.5 transition-all ${showVerifiedOnly ? 'left-4.5' : 'left-0.5'}`} />
                </div>
                <span className="text-xs text-gray-300">Verified businesses only</span>
                <BadgeCheck size={12} className="text-emerald-400" />
              </label>
              {activeFilters > 0 && (
                <button onClick={() => { setSelectedCategory('All'); setSelectedDistrict('All'); setShowVerifiedOnly(false); }}
                  className="text-xs text-rose-400 hover:text-rose-300 flex items-center gap-1">
                  <X size={11} /> Clear all filters
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-6 pb-28 md:pb-12">

        <div className="glass-card rounded-2xl p-5 mb-6 border border-emerald-500/20">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <div className="flex items-center gap-2 mb-1 text-emerald-400 text-xs font-bold uppercase">
                <Navigation size={14} /> Map Search
              </div>
              <h2 className="font-outfit font-bold text-white text-lg">Near me businesses</h2>
              <p className="text-sm text-gray-400 mt-1">
                Location wise jobs/businesses பாருங்கள். Direction button மூலம் Google Maps-க்கு போகலாம்.
              </p>
            </div>
            <button
              onClick={() => setSelectedDistrict('Theni')}
              className="btn-gradient px-5 py-3 rounded-xl text-sm font-semibold relative z-10 flex items-center justify-center gap-2"
            >
              <MapPin size={15} /> Use Theni Location
            </button>
          </div>
        </div>

        {/* Stats + Sort */}
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="font-outfit font-bold text-xl text-white">
              {loading ? 'Loading...' : `${filtered.length} Business${filtered.length !== 1 ? 'es' : ''}`}
            </h1>
            <p className="text-sm text-gray-500 mt-0.5">
              {selectedCategory !== 'All' ? selectedCategory : 'All categories'}
              {selectedDistrict !== 'All' ? ` in ${selectedDistrict}` : ' across Tamil Nadu'}
            </p>
          </div>
          <select value={sortBy} onChange={e => setSortBy(e.target.value)}
            className="bg-white/5 border border-white/10 rounded-xl px-3 py-2 text-xs text-gray-300 outline-none">
            {SORT_OPTIONS.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
          </select>
        </div>

        {/* Category quick pills */}
        <div className="-mx-4 sm:mx-0 overflow-x-auto no-scrollbar mb-6 px-4 sm:px-0">
          <div className="flex w-max gap-2">
          {CATEGORIES.slice(1).map(cat => (
            <button key={cat} onClick={() => setSelectedCategory(selectedCategory === cat ? 'All' : cat)}
              className={`px-4 py-2 rounded-xl text-xs font-medium whitespace-nowrap border transition-all shrink-0
                ${selectedCategory === cat ? 'bg-violet-600 text-white border-violet-600' : 'bg-white/5 border-white/10 text-gray-400 hover:text-white'}`}>
              {cat}
            </button>
          ))}
          </div>
        </div>

        {/* Loading State */}
        {loading ? (
          <div className="glass-card rounded-2xl p-16 text-center">
            <Loader2 size={32} className="text-violet-400 mx-auto mb-4 animate-spin" />
            <p className="text-sm text-gray-400">Loading businesses...</p>
          </div>
        ) : filtered.length === 0 ? (
          <div className="glass-card rounded-2xl p-12 text-center">
            <div className="w-16 h-16 rounded-2xl bg-violet-500/10 flex items-center justify-center mx-auto mb-4">
              <Building2 size={28} className="text-violet-400" />
            </div>
            <h3 className="text-lg font-semibold text-white mb-2">
              {businesses.length === 0 ? 'No businesses registered yet' : 'No businesses match your filters'}
            </h3>
            <p className="text-gray-400 text-sm mb-6 max-w-md mx-auto">
              {businesses.length === 0
                ? 'Be the first to register your business on THENIJOBS and get discovered by thousands of customers across Tamil Nadu.'
                : 'Try adjusting your search or filters to find what you are looking for.'
              }
            </p>
            {businesses.length === 0 ? (
              <Link href="/company/register" className="btn-gradient px-6 py-3 rounded-2xl text-sm font-semibold relative z-10 inline-flex items-center gap-2">
                Register Your Business <ArrowRight size={15} />
              </Link>
            ) : (
              <button onClick={() => { setSearch(''); setSelectedCategory('All'); setSelectedDistrict('All'); setShowVerifiedOnly(false); }}
                className="btn-outline-glass px-5 py-2 rounded-xl text-sm font-medium">Clear Filters</button>
            )}
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 gap-4">
            {filtered.map(biz => (
              <div key={biz.id} className="premium-card rounded-2xl p-5 flex flex-col gap-4 group">
                <div className="flex gap-3">
                  <div className="w-14 h-14 rounded-2xl bg-white/5 border border-white/10 flex items-center justify-center text-sm font-bold text-violet-400 shrink-0">
                    {biz.logo}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between gap-1">
                      <div className="min-w-0">
                        <div className="flex items-center gap-1.5 flex-wrap">
                          <h2 className="font-semibold text-white text-sm leading-tight truncate">{biz.name}</h2>
                          {biz.isVerified && <BadgeCheck size={14} className="text-emerald-400 shrink-0" />}
                        </div>
                        {biz.isPremium && <span className="badge-premium text-[9px] mt-0.5 inline-block">FEATURED</span>}
                        {biz.isNew && !biz.isPremium && <span className="text-[9px] px-1.5 py-0.5 rounded-full bg-cyan-500/15 text-cyan-400 border border-cyan-500/20 font-bold inline-block mt-0.5">NEW</span>}
                      </div>
                    </div>
                    <p className="text-xs text-gray-500 mt-1 line-clamp-1">{biz.tagline}</p>
                  </div>
                </div>

                <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-gray-500">
                  <span className="text-violet-400 font-medium">{biz.category}</span>
                  <span className="flex items-center gap-1"><MapPin size={10} />{biz.district}</span>
                  {biz.rating > 0 && <span className="flex items-center gap-1"><Star size={10} className="fill-amber-400 text-amber-400" />{biz.rating} ({biz.reviews})</span>}
                  {biz.jobs > 0 && <span className="flex items-center gap-1 text-cyan-400"><Briefcase size={10} />{biz.jobs} jobs</span>}
                </div>

                <div className="flex gap-2 mt-auto">
                  <Link href={`/company/${biz.slug}`}
                    className="flex-1 btn-gradient py-2.5 rounded-xl text-xs font-semibold relative z-10 text-center flex items-center justify-center gap-1.5">
                    View Profile <ArrowRight size={12} />
                  </Link>
                  {biz.phone && (
                    <a href={`tel:${biz.phone}`} className="btn-outline-glass px-3 py-2.5 rounded-xl text-xs font-medium flex items-center gap-1" aria-label={`Call ${biz.name}`}>
                      <Phone size={12} />
                    </a>
                  )}
                  {biz.whatsapp && (
                    <a href={`https://wa.me/${biz.whatsapp.replace(/[^0-9]/g, '')}`} target="_blank" rel="noopener noreferrer" className="btn-outline-glass px-3 py-2.5 rounded-xl text-xs font-medium flex items-center gap-1" aria-label={`WhatsApp ${biz.name}`}>
                      <MessageCircle size={12} />
                    </a>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Register CTA */}
        <div className="mt-10 glass-card rounded-2xl p-6 text-center border border-violet-500/20">
          <div className="text-3xl mb-3">🚀</div>
          <h3 className="font-outfit font-bold text-white text-lg mb-1">List Your Business Free</h3>
          <p className="text-gray-400 text-sm mb-4">Get your own Google-ready SEO page on THENIJOBS</p>
          <Link href="/company/register" className="btn-gradient px-6 py-3 rounded-2xl text-sm font-semibold relative z-10 inline-flex items-center gap-2">
            Register Now — It&apos;s Free <ArrowRight size={15} />
          </Link>
        </div>
      </div>
      <BottomNav />
    </main>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import Header from '@/components/navigation/Header';
import BottomNav from '@/components/navigation/BottomNav';
import {
  Building2, MapPin, Phone, Mail, Globe, FileText, Image,
  Video, Clock, ChevronRight, Check, ArrowLeft, ArrowRight,
  Loader2, Upload, Plus, X, BadgeCheck
} from 'lucide-react';
import { BUSINESS_CATEGORIES, TN_DISTRICTS } from '@/lib/types';
import { useAuth } from '@/contexts/AuthContext';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase/config';
import { useUploadFile } from '@/hooks/useStorage';

const STEPS = [
  { id: 1, label: 'Basic Info', icon: Building2 },
  { id: 2, label: 'Contact & Location', icon: MapPin },
  { id: 3, label: 'Media Upload', icon: Image },
  { id: 4, label: 'Details & Social', icon: Globe },
  { id: 5, label: 'Services', icon: FileText },
  { id: 6, label: 'Preview & Submit', icon: Check },
];

const COMPANY_SIZES = ['1–10', '11–50', '51–200', '201–500', '500+'];
const HOURS = ['08:00 AM', '09:00 AM', '10:00 AM'] as const;

export default function CompanyRegisterPage() {
  const router = useRouter();
  const { user } = useAuth();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [services, setServices] = useState<string[]>([]);
  const [newService, setNewService] = useState('');

  const { uploadFile: uploadLogo, loading: logoLoading, progress: logoProgress } = useUploadFile();
  const { uploadFile: uploadCover, loading: coverLoading, progress: coverProgress } = useUploadFile();
  const { uploadFile: uploadGallery, loading: galleryLoading, progress: galleryProgress } = useUploadFile();

  const [form, setForm] = useState({
    name: '', category: '', subcategory: '', foundedYear: '',
    companySize: '', gstNumber: '', registrationNumber: '', description: '',
    phone: '', alternatePhone: '', email: '', website: '', whatsapp: '',
    address: '', district: '', state: 'Tamil Nadu', country: 'India',
    facebook: '', instagram: '', linkedin: '', youtube: '',
    openFrom: '09:00 AM', openTo: '06:00 PM',
    logoUrl: '', coverUrl: '', galleryUrls: [] as string[],
  });

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    try {
      const path = `companies/${user.uid}/logo/${Date.now()}_${file.name}`;
      const downloadUrl = await uploadLogo(file, path, {
        allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
        maxSizeBytes: 2 * 1024 * 1024
      });
      setForm(f => ({ ...f, logoUrl: downloadUrl }));
    } catch (err: any) {
      alert(err.message || 'Logo upload failed');
    }
  };

  const handleCoverUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user) return;
    try {
      const path = `companies/${user.uid}/cover/${Date.now()}_${file.name}`;
      const downloadUrl = await uploadCover(file, path, {
        allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
        maxSizeBytes: 5 * 1024 * 1024
      });
      setForm(f => ({ ...f, coverUrl: downloadUrl }));
    } catch (err: any) {
      alert(err.message || 'Cover upload failed');
    }
  };

  const handleGalleryUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0 || !user) return;
    if (form.galleryUrls.length + files.length > 10) {
      alert('You can upload a maximum of 10 gallery images.');
      return;
    }
    try {
      const urls: string[] = [];
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const path = `companies/${user.uid}/gallery/${Date.now()}_${i}_${file.name}`;
        const downloadUrl = await uploadGallery(file, path, {
          allowedTypes: ['image/png', 'image/jpeg', 'image/jpg'],
          maxSizeBytes: 3 * 1024 * 1024
        });
        urls.push(downloadUrl);
      }
      setForm(f => ({ ...f, galleryUrls: [...f.galleryUrls, ...urls] }));
    } catch (err: any) {
      alert(err.message || 'Gallery image upload failed');
    }
  };

  const update = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));
  const addService = () => { if (newService.trim()) { setServices(s => [...s, newService.trim()]); setNewService(''); } };
  const removeService = (i: number) => setServices(s => s.filter((_, idx) => idx !== i));

  const handleSubmit = async () => {
    if (!user) {
      alert('Please login to register a business.');
      router.push('/login?redirect=/company/register');
      return;
    }
    setLoading(true);
    try {
      const slug = form.name
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/(^-|-$)+/g, '');

      await addDoc(collection(db, 'companies'), {
        ...form,
        foundedYear: form.foundedYear ? parseInt(form.foundedYear) : '',
        services,
        ownerId: user.uid,
        status: 'pending',
        isVerified: false,
        isPremium: false,
        rating: 0,
        reviewCount: 0,
        viewCount: 0,
        enquiryCount: 0,
        followerCount: 0,
        slug,
        verificationBadges: {
          mobileVerified: !!form.phone,
          emailVerified: !!form.email,
          gstVerified: !!form.gstNumber,
          businessVerified: false,
        },
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp(),
      });
      alert('Business registered successfully! Pending admin approval.');
      router.push('/employer/dashboard');
    } catch (err) {
