          <Loader2 size={36} className="text-cyan-400 animate-spin mb-4" />
          <p className="text-sm text-gray-400">Loading candidate applications...</p>
        </div>
      ) : (
        <>
          {/* Pipeline Tabs */}
          <div className="flex items-center gap-1 overflow-x-auto no-scrollbar bg-white/[0.03] rounded-xl p-1 border border-white/[0.06]">
            {PIPELINE_TABS.map((t) => (
              <button
                key={t.value}
                onClick={() => setPipelineTab(t.value)}
                className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition-all ${
                  pipelineTab === t.value
                    ? 'bg-cyan-500/15 text-cyan-300 border border-cyan-500/20'
                    : 'text-gray-400 hover:text-white hover:bg-white/[0.04]'
                }`}
              >
                {t.label}
                <span className="ml-1.5 text-[10px]">({counts[t.value as keyof typeof counts]})</span>
              </button>
            ))}
          </div>

          {/* Filter Bar */}
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1 max-w-sm">
              <Search size={16} className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-500" />
              <input
                type="text"
                placeholder="Search candidates..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white placeholder:text-gray-600 focus:border-cyan-500/40 outline-none transition-all"
              />
            </div>
            <select
              value={jobFilter}
              onChange={(e) => setJobFilter(e.target.value)}
              className="px-4 py-2.5 rounded-xl bg-white/[0.04] border border-white/[0.08] text-sm text-white focus:border-cyan-500/40 outline-none transition-all"
            >
              {jobOptions.map((j) => (
                <option key={j} value={j}>{j}</option>
              ))}
            </select>
          </div>

          {/* Candidate Cards */}
          <div className="space-y-3">
            {pipelineTab === 'ai_recommended' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {matchingCandidates.length === 0 ? (
                  <div className="col-span-2 glass-card rounded-2xl p-12 text-center">
                    <Sparkles size={32} className="text-gray-600 mx-auto mb-3 animate-pulse" />
                    <p className="text-sm text-gray-400">No matching candidates recommended</p>
                    <p className="text-xs text-gray-600 mt-1">Make sure you have active jobs with skills configured</p>
                  </div>
                ) : (
                  matchingCandidates.map((c: any) => (
                    <CandidateSuggestionCard
                      key={c.candidateId}
                      candidate={c}
                      onSendInvite={() => handleSendInvite(c.candidateId, c.candidateName)}
                      onViewProfile={() => {
                        const seeker = seekerProfiles.find((sp: any) => sp.id === c.candidateId);
                        if (seeker) {
                          alert(`Skills: ${seeker.skills?.join(', ')}\nDistrict: ${seeker.district}`);
                        }
                      }}
                    />
                  ))
                )}
              </div>
            ) : (
              filtered.map((candidate) => {
                const status = statusConfig[candidate.status || 'applied'] || statusConfig.applied;
                const isExpanded = expandedId === candidate.id;
                return (
                  <div
                    key={candidate.id}
                    className="glass-card rounded-2xl overflow-hidden hover:border-white/15 transition-all"
                  >
                    {/* Main Row */}
                    <div className="p-5">
                      <div className="flex flex-col lg:flex-row lg:items-center gap-4">
                        {/* Avatar + Info */}
                        <div className="flex items-center gap-4 flex-1 min-w-0">
                          <div className="w-11 h-11 rounded-full bg-gradient-to-br from-violet-500/30 to-cyan-500/30 flex items-center justify-center flex-shrink-0">
                            <span className="text-xs font-bold text-white">{getInitials(candidate.seekerName)}</span>
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                              <p className="text-sm font-semibold text-white">{candidate.seekerName || 'Candidate'}</p>
                              <span className={`px-2 py-0.5 rounded-full text-[9px] font-bold uppercase ${status.bg} ${status.text}`}>
                                {status.label}
                              </span>
                            </div>
                            <p className="text-xs text-gray-400 mt-0.5 flex items-center gap-2 flex-wrap">
                              <span className="flex items-center gap-1">
                                <Briefcase size={11} /> {candidate.jobTitle}
                              </span>
                              <span className="flex items-center gap-1">
                                <Clock size={11} /> Applied {candidate.createdAt ? new Date(candidate.createdAt).toLocaleDateString() : 'Recently'}
                              </span>
                            </p>
                          </div>
                        </div>

                        {/* Actions */}
                        <div className="flex items-center gap-2 flex-wrap">
                          {actionLoading === candidate.id ? (
                            <Loader2 size={16} className="text-cyan-400 animate-spin" />
                          ) : (
                            <>
                              <button
                                onClick={() => setExpandedId(isExpanded ? null : candidate.id)}
                                className="p-2 rounded-lg bg-white/[0.04] text-gray-400 hover:bg-white/[0.08] hover:text-white transition-all"
                                title="View Details"
                              >
                                <Eye size={14} />
                              </button>
                              {candidate.resumeUrl && candidate.resumeUrl !== '#' && (
                                <a
                                  href={candidate.resumeUrl}
                                  target="_blank"
                                  rel="noreferrer"
                                  className="p-2 rounded-lg bg-cyan-500/10 text-cyan-400 hover:bg-cyan-500/20 transition-all flex items-center justify-center"
                                  title="Download Resume"
                                >
                                  <Download size={14} />
                                </a>
                              )}
                              {candidate.status !== 'shortlisted' && candidate.status !== 'selected' && (
                                <button
                                  onClick={() => handleUpdateStatus(candidate.id, 'shortlisted', candidate.seekerId, candidate.jobTitle)}
                                  className="p-2 rounded-lg bg-emerald-500/10 text-emerald-400 hover:bg-emerald-500/20 transition-all"
                                  title="Shortlist"
                                >
                                  <CheckCircle size={14} />
                                </button>
                              )}
                              {candidate.status !== 'selected' && (
                                <button
                                  onClick={() => handleUpdateStatus(candidate.id, 'selected', candidate.seekerId, candidate.jobTitle)}
                                  className="p-2 rounded-lg bg-purple-500/10 text-purple-400 hover:bg-purple-500/20 transition-all"
                                  title="Select / Hire"
                                >
                                  <Star size={14} />
                                </button>
                              )}
                              {candidate.status !== 'rejected' && (
                                <button
                                  onClick={() => handleUpdateStatus(candidate.id, 'rejected', candidate.seekerId, candidate.jobTitle)}
                                  className="p-2 rounded-lg bg-rose-500/10 text-rose-400 hover:bg-rose-500/20 transition-all"
                                  title="Reject"
                                >
                                  <XCircle size={14} />
                                </button>
                              )}
                            </>
                          )}
                        </div>
                      </div>
                    </div>

                    {/* Expanded Detail Panel */}
                    {isExpanded && (
                      <CandidateDetailPanel
                        seekerId={candidate.seekerId}
                        applicationId={candidate.id}
                        currentStatus={candidate.status || 'applied'}
                        initialNotes={candidate.employerNote}
                        companyId={companyId}
                        companyName={company?.name || 'Company'}
                        jobId={candidate.jobId}
                        jobTitle={candidate.jobTitle}
                        seekerName={candidate.seekerName}
                        statusTimestamps={candidate.statusTimestamps}
                        onNotesUpdated={(newNotes) => {
                          candidate.employerNote = newNotes;
                        }}
                        onUpdateStatus={async (newStatus) => {
                          await handleUpdateStatus(candidate.id, newStatus, candidate.seekerId, candidate.jobTitle);
                        }}
                        onStatusUpdated={(newStatus) => {
                          candidate.status = newStatus;
                          setExpandedId(null);
                        }}
                      />
                    )}
                  </div>
                );
              })
            )}

            {pipelineTab !== 'ai_recommended' && filtered.length === 0 && (
              <div className="glass-card rounded-2xl p-12 text-center">
                <Users2 size={32} className="text-gray-600 mx-auto mb-3" />
                <p className="text-sm text-gray-400">No candidates found</p>
                <p className="text-xs text-gray-600 mt-1">Adjust filters or wait for new applications</p>
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import {
  Camera, Upload, Building2, Phone, Mail, Globe, MapPin,
  Link2, Heart, Briefcase as LinkedinIcon, Play, Plus, X, Save,
  CheckCircle, AlertCircle, Shield, Smartphone, FileText,
  ImagePlus, Trash2, MessageCircle, Loader2
} from 'lucide-react';
import { TN_DISTRICTS } from '@/lib/types';
import { useAuth } from '@/hooks/useAuth';
import { useCollection } from '@/hooks/useFirestore';
import { useUploadFile } from '@/hooks/useStorage';
import { createDocument, updateDocument } from '@/lib/firebase/firestoreService';
import { where } from 'firebase/firestore';

const DEFAULT_COMPANY = {
  name: '',
  tagline: '',
  logoUrl: '',
  coverUrl: '',
  description: '',
  phone: '',
  email: '',
  whatsapp: '',
  website: '',
  address: '',
  district: '',
  facebook: '',
  instagram: '',
  linkedin: '',
  youtube: '',
  gallery: ['', '', '', ''],
  branches: [] as any[],
  verification: {
    mobile: false,
    email: false,
    gst: false,
    business: false,
  },
};

function calcCompletion(data: typeof DEFAULT_COMPANY): number {
  const fields = [
    data.name, data.description, data.phone, data.email,
    data.address, data.district, data.logoUrl, data.coverUrl,
    data.website, data.whatsapp, data.facebook
  ];
  const filled = fields.filter(Boolean).length;
  return Math.round((filled / fields.length) * 100);
}

export default function CompanyProfilePage() {
  const { user } = useAuth();

  // 1. Fetch employer's company
  const { data: companies, loading: companyLoading } = useCollection<any>('companies', [
    where('ownerId', '==', user?.uid || '')
  ], { skip: !user?.uid });

  const resolvedCompany = companies[0];

  const [company, setCompany] = useState(DEFAULT_COMPANY);
  const [charCount, setCharCount] = useState(0);
  const [newBranch, setNewBranch] = useState({ name: '', address: '', district: '' });
  const [showBranchForm, setShowBranchForm] = useState(false);
  const [saving, setSaving] = useState(false);

  const coverInputRef = useRef<HTMLInputElement>(null);
  const logoInputRef = useRef<HTMLInputElement>(null);
  const galleryInputRefs = [
    useRef<HTMLInputElement>(null),
    useRef<HTMLInputElement>(null),
    useRef<HTMLInputElement>(null),
    useRef<HTMLInputElement>(null)
  ];

  const { uploadFile, progress: uploadProgress, loading: uploading } = useUploadFile();

  useEffect(() => {
    if (resolvedCompany) {
      setCompany({
        ...DEFAULT_COMPANY,
        ...resolvedCompany,
        gallery: resolvedCompany.gallery || DEFAULT_COMPANY.gallery,
        branches: resolvedCompany.branches || DEFAULT_COMPANY.branches,
        verification: resolvedCompany.verification || DEFAULT_COMPANY.verification,
      });
      setCharCount(resolvedCompany.description?.length || 0);
    }
  }, [resolvedCompany]);

  const completion = calcCompletion(company);

  const update = (key: string, value: any) => {
    setCompany((prev) => ({ ...prev, [key]: value }));
  };

  const handleDescChange = (value: string) => {
    if (value.length <= 1000) {
      update('description', value);
      setCharCount(value.length);
    }
  };

  const addBranch = () => {
    if (newBranch.name && newBranch.address && newBranch.district) {
      setCompany((prev) => ({
        ...prev,
        branches: [...(prev.branches || []), { id: Date.now().toString(), ...newBranch }],
      }));
      setNewBranch({ name: '', address: '', district: '' });
      setShowBranchForm(false);
    }
  };

  const removeBranch = (id: string) => {
    setCompany((prev) => ({
      ...prev,
      branches: (prev.branches || []).filter((b) => b.id !== id),
    }));
  };

  const handleUploadCover = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user?.uid) return;
    try {
      const url = await uploadFile(file, `companies/${user.uid}/cover/${Date.now()}_${file.name}`);
      update('coverUrl', url);
    } catch (err) {
      console.error(err);
      alert('Upload failed: ' + (err as Error).message);
    }
  };

  const handleUploadLogo = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !user?.uid) return;
    try {
      const url = await uploadFile(file, `companies/${user.uid}/logo/${Date.now()}_${file.name}`);
      update('logoUrl', url);
    } catch (err) {
      console.error(err);
      alert('Upload failed: ' + (err as Error).message);
    }
  };

  const handleUploadGallery = async (e: React.ChangeEvent<HTMLInputElement>, index: number) => {
    const file = e.target.files?.[0];
    if (!file || !user?.uid) return;
    try {
      const url = await uploadFile(file, `companies/${user.uid}/gallery/${index}_${Date.now()}_${file.name}`);
      const newGallery = [...company.gallery];
      newGallery[index] = url;
      setCompany(prev => ({ ...prev, gallery: newGallery }));
    } catch (err) {
      console.error(err);
      alert('Upload failed: ' + (err as Error).message);
    }
  };

  const handleSave = async () => {
    if (!company.name) {
      alert('Please fill in the Company Name.');
      return;
    }
    if (!company.phone || !company.email) {
      alert('Please fill in both Phone and Email.');
      return;
    }
    if (!company.address || !company.district) {
      alert('Please fill in Address and District.');
      return;
    }
    setSaving(true);
    try {
      const docData = {
        name: company.name,
        tagline: company.tagline,
        logoUrl: company.logoUrl,
        coverUrl: company.coverUrl,
        description: company.description,
        phone: company.phone,
        email: company.email,
        whatsapp: company.whatsapp,
        website: company.website,
        address: company.address,
        district: company.district,
        facebook: company.facebook,
        instagram: company.instagram,
        linkedin: company.linkedin,
        youtube: company.youtube,
        gallery: company.gallery,
        branches: company.branches,
        verification: company.verification,
        updatedAt: new Date()
      };

      if (resolvedCompany?.id) {
        await updateDocument('companies', resolvedCompany.id, docData);
        alert('Company profile updated successfully!');
      } else {
        await createDocument('companies', {
          ...docData,
          ownerId: user?.uid,
          verificationStatus: 'pending',
          isActive: false,
          viewCount: 0
        });
        alert('Company profile created successfully! It is currently pending admin approval.');
      }
    } catch (err) {
      console.error(err);
      alert('Failed to save company profile.');
    } finally {
      setSaving(false);
    }
  };

  if (companyLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 font-outfit">
        <Loader2 size={36} className="text-cyan-400 animate-spin mb-4" />
        <p className="text-sm text-gray-400">Loading company profile...</p>
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in-up font-outfit">
      {/* Page Header */}
      <div>
        <h1 className="text-2xl font-bold text-white font-outfit">Company Profile</h1>
        <p className="text-sm text-gray-400 mt-1">Manage your company information and branding</p>
      </div>

      {/* Profile Completion Banner */}
      {completion < 100 && (
        <div className="glass-card rounded-2xl p-4 border border-amber-500/20 bg-amber-500/5">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-amber-500/10 flex items-center justify-center flex-shrink-0">
              <AlertCircle size={18} className="text-amber-400" />
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-amber-300">
                Profile {completion}% Complete
              </p>
              <p className="text-xs text-gray-400 mt-0.5">
                Complete your profile to attract more candidates and build trust
              </p>
            </div>
          </div>
          <div className="mt-3 h-2 bg-white/5 rounded-full overflow-hidden">
            <div
              className="h-full bg-gradient-to-r from-amber-500 to-emerald-500 rounded-full transition-all duration-500"
              style={{ width: `${completion}%` }}
