'use client';

import { useEffect, useState, useCallback, useRef } from 'react';
import {
  collection,
  query,
  orderBy,
  limit,
  onSnapshot,
  doc,
  updateDoc,
  serverTimestamp,
} from 'firebase/firestore';
import { db } from '@/lib/firebase/config';
import { useAuth } from '@/hooks/useAuth';
import {
  createConversation,
  sendChatMessage,
  markMessagesRead,
  setTypingStatus,
} from '@/lib/firebase/firestoreService';

interface Message {
  id: string;
  senderId: string;
  senderName: string;
  senderRole: string;
  text: string;
  type: 'text' | 'image' | 'file' | 'system';
  read: boolean;
  readAt?: any;
  createdAt: any;
  attachments?: { type: string; url: string; name: string; size?: number }[];
}

interface ConversationData {
  id: string;
  participants: string[];
  participantNames: Record<string, string>;
  participantRoles: Record<string, string>;
  participantPhotos?: Record<string, string>;
  jobId?: string;
  jobTitle?: string;
  lastMessage: string;
  lastMessageAt: any;
  lastMessageSenderId?: string;
  typingUsers: string[];
  unreadCounts: Record<string, number>;
  status: string;
}

/**
 * Real-time chat hook for a specific conversation.
 *
 * Subscribes to messages in real-time, handles sending,
 * typing indicators, and read receipts.
 */
export function useChat(conversationId: string | null) {
  const { user } = useAuth();
  const [messages, setMessages] = useState<Message[]>([]);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [otherUserTyping, setOtherUserTyping] = useState(false);
  const typingTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Real-time message listener
  useEffect(() => {
    if (!conversationId || !user?.uid) {
      setMessages([]);
      setLoading(false);
      return;
    }

    setLoading(true);
    const msgsRef = collection(db, 'conversations', conversationId, 'messages');
    const q = query(msgsRef, orderBy('createdAt', 'asc'), limit(200));

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const msgs = snapshot.docs.map((d) => ({
          id: d.id,
          ...d.data(),
        })) as Message[];
        setMessages(msgs);
        setLoading(false);

        // Auto-mark messages as read
        const unreadFromOthers = snapshot.docs.filter(
          (d) => d.data().senderId !== user.uid && !d.data().read
        );
        if (unreadFromOthers.length > 0) {
          markMessagesRead(conversationId, user.uid).catch(console.error);
        }
      },
      (err) => {
        console.error('[useChat] messages error:', err);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [conversationId, user?.uid]);

  // Typing indicator listener
  useEffect(() => {
    if (!conversationId || !user?.uid) return;

    const convRef = doc(db, 'conversations', conversationId);
    const unsubscribe = onSnapshot(convRef, (snap) => {
      if (snap.exists()) {
        const data = snap.data();
        const typingUsers = (data.typingUsers || []) as string[];
        setOtherUserTyping(typingUsers.some((uid: string) => uid !== user.uid));
      }
    });

    return () => unsubscribe();
  }, [conversationId, user?.uid]);

  // Send message
  const send = useCallback(
    async (text: string, attachments?: File[]) => {
      if (!text.trim() || !conversationId || !user?.uid) return;

      setSending(true);
      try {
        await sendChatMessage(conversationId, {
          senderId: user.uid,
          senderName: user.displayName || 'User',
          senderRole: (user as any).role || 'user',
          text: text.trim(),
          type: 'text',
        });

        // Clear typing indicator
        await setTypingStatus(conversationId, user.uid, false);
      } catch (err) {
        console.error('[useChat] send error:', err);
        throw err;
      } finally {
        setSending(false);
      }
    },
    [conversationId, user]
  );

  // Set typing indicator with auto-clear
  const setTyping = useCallback(
    async (isTyping: boolean) => {
      if (!conversationId || !user?.uid) return;

      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }

      try {
        await setTypingStatus(conversationId, user.uid, isTyping);

        // Auto-clear typing after 3 seconds of inactivity
        if (isTyping) {
          typingTimeoutRef.current = setTimeout(async () => {
            await setTypingStatus(conversationId, user.uid, false);
          }, 3000);
        }
      } catch (err) {
        console.error('[useChat] typing error:', err);
      }
    },
    [conversationId, user]
  );

  // Start a new conversation
  const startConversation = useCallback(
    async (
      otherUserId: string,
      otherUserName: string,
      otherUserRole: string,
      jobId?: string,
      jobTitle?: string,
    ) => {
      if (!user?.uid) return null;

      try {
        const convId = await createConversation({
          participants: [user.uid, otherUserId],
          participantNames: {
            [user.uid]: user.displayName || 'User',
            [otherUserId]: otherUserName,
          },
          participantRoles: {
            [user.uid]: (user as any).role || 'user',
            [otherUserId]: otherUserRole,
          },
          jobId,
          jobTitle,
        });
        return convId;
      } catch (err) {
        console.error('[useChat] create conversation error:', err);
        return null;
      }
    },
    [user]
  );

  // Cleanup typing timeout on unmount
  useEffect(() => {
    return () => {
      if (typingTimeoutRef.current) {
        clearTimeout(typingTimeoutRef.current);
      }
    };
  }, []);

  return {
    messages,
    loading,
    sending,
    otherUserTyping,
    send,
    setTyping,
    startConversation,
  };
}

/**
 * Hook for listing all conversations for the current user.
 */
export function useConversationList() {
  const { user } = useAuth();
  const [conversations, setConversations] = useState<ConversationData[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!user?.uid) {
      setConversations([]);
      setLoading(false);
      return;
    }

    setLoading(true);
    const q = query(
      collection(db, 'conversations'),
      // array-contains works for checking if user is a participant
    );

    // We use a broader query and filter client-side because
    // Firestore doesn't support array-contains + orderBy on different fields easily
    const unsubscribe = onSnapshot(
      collection(db, 'conversations'),
      (snapshot) => {
        const convs = snapshot.docs
          .map((d) => ({ id: d.id, ...d.data() }) as ConversationData)
          .filter((c) => c.participants?.includes(user.uid) && c.status === 'active')
          .sort((a, b) => {
            const aTime = a.lastMessageAt?.seconds || 0;
            const bTime = b.lastMessageAt?.seconds || 0;
            return bTime - aTime;
          });
        setConversations(convs);
        setLoading(false);
      },
      (err) => {
        console.error('[useConversationList] error:', err);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [user?.uid]);

  // Calculate total unread
  const totalUnread = conversations.reduce((sum, c) => {
    return sum + (c.unreadCounts?.[user?.uid || ''] || 0);
  }, 0);

  return { conversations, loading, totalUnread };
}

'use client';

import { useEffect, useState, useCallback, useRef } from 'react';
import {
  collection,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  getDoc,
  onSnapshot,
  query,
  type QueryConstraint,
  type DocumentData,
  type Query,
  serverTimestamp,
} from 'firebase/firestore';
import { db } from '@/lib/firebase/config';

// ───────────────────────────── Types ─────────────────────────────

export interface UseCollectionOptions {
  /** Skip the real-time listener (data will stay empty) */
  skip?: boolean;
}

export interface UseCollectionReturn<T> {
  data: T[];
  loading: boolean;
  error: string | null;
  /** Force re-attach the listener */
  refresh: () => void;
}

export interface UseDocumentReturn<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
}

export interface UseMutationReturn {
  loading: boolean;
  error: string | null;
}

// ───────────────────────────── useCollection ─────────────────────

/**
 * Subscribe to a Firestore collection in real-time with optional query constraints.
 *
 * @example
 * ```ts
 * const { data: jobs, loading } = useCollection<Job>('jobs', [
 *   where('isActive', '==', true),
 *   orderBy('createdAt', 'desc'),
 *   limit(20),
 * ]);
 * ```
 */
export function useCollection<T extends DocumentData>(
  collectionName: string,
  queryConstraints: QueryConstraint[] = [],
  options: UseCollectionOptions = {},
): UseCollectionReturn<T> {
  const [data, setData] = useState<T[]>([]);
  const [loading, setLoading] = useState(!options.skip);
  const [error, setError] = useState<string | null>(null);
  const [refreshKey, setRefreshKey] = useState(0);

  // Serialise constraints so the effect doesn't re-run on every render
  // when the caller constructs constraints inline.
  const constraintsRef = useRef(queryConstraints);
  constraintsRef.current = queryConstraints;

  const refresh = useCallback(() => setRefreshKey((k) => k + 1), []);

  useEffect(() => {
    if (options.skip) return;

    setLoading(true);
    setError(null);

    let q: Query<DocumentData>;
    if (constraintsRef.current.length > 0) {
      q = query(collection(db, collectionName), ...constraintsRef.current);
    } else {
      q = collection(db, collectionName);
    }

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        const docs = snapshot.docs.map(
          (d) => ({ id: d.id, ...d.data() }) as unknown as T,
        );
        setData(docs);
        setLoading(false);
      },
      (err) => {
        console.error(`[useCollection] ${collectionName}:`, err);
        setError(err.message);
        setLoading(false);
      },
    );

    return () => unsubscribe();

  }, [collectionName, options.skip, refreshKey]);

  return { data, loading, error, refresh };
}

// ───────────────────────────── useDocument ────────────────────────

/**
 * Subscribe to a single Firestore document in real-time.
 *
 * @example
 * ```ts
 * const { data: user, loading } = useDocument<User>('users', userId);
 * ```
 */
export function useDocument<T extends DocumentData>(
  collectionName: string,
  docId: string | null | undefined,
): UseDocumentReturn<T> {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(!!docId);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!docId) {
      setData(null);
      setLoading(false);
      return;
    }

    setLoading(true);
    setError(null);

    const unsubscribe = onSnapshot(
      doc(db, collectionName, docId),
      (snap) => {
        if (snap.exists()) {
          setData({ id: snap.id, ...snap.data() } as unknown as T);
        } else {
          setData(null);
        }
        setLoading(false);
      },
      (err) => {
        console.error(`[useDocument] ${collectionName}/${docId}:`, err);
        setError(err.message);
        setLoading(false);
      },
    );

    return () => unsubscribe();
  }, [collectionName, docId]);

  return { data, loading, error };
}

// ───────────────────────────── useAddDocument ────────────────────

/**
 * Add a new document to a Firestore collection.
 *
 * @example
 * ```ts
 * const { addDocument, loading } = useAddDocument('jobs');
 * await addDocument({ title: 'React Dev', ... });
 * ```
 */
export function useAddDocument(collectionName: string) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const addDocument = useCallback(
    async (data: DocumentData): Promise<string> => {
      setLoading(true);
      setError(null);
      try {
        const docRef = await addDoc(collection(db, collectionName), {
          ...data,
          createdAt: serverTimestamp(),
          updatedAt: serverTimestamp(),
        });
        return docRef.id;
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Failed to add document';
        setError(message);
        throw err;
      } finally {
        setLoading(false);
      }
    },
    [collectionName],
  );

  return { addDocument, loading, error };
}

// ───────────────────────────── useUpdateDocument ─────────────────

/**
 * Update an existing Firestore document.
 *
 * @example
 * ```ts
 * const { updateDocument } = useUpdateDocument('jobs');
 * await updateDocument(jobId, { isActive: false });
 * ```
 */
export function useUpdateDocument(collectionName: string) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const updateDocument = useCallback(
    async (docId: string, data: Partial<DocumentData>): Promise<void> => {
      setLoading(true);
      setError(null);
      try {
        await updateDoc(doc(db, collectionName, docId), {
          ...data,
          updatedAt: serverTimestamp(),
        });
      } catch (err) {
        const message = err instanceof Error ? err.message : 'Failed to update document';
        setError(message);
        throw err;
      } finally {
        setLoading(false);
      }
    },
    [collectionName],
  );

  return { updateDocument, loading, error };
}

// ───────────────────────────── useDeleteDocument ─────────────────

/**
 * Delete a Firestore document.
 *
 * @example
 * ```ts
